PRAGMA journal_mode=WAL;
PRAGMA foreign_keys=OFF;

-- Schema
CREATE TABLE published_posts (
	id INTEGER NOT NULL, 
	post_id VARCHAR(36) NOT NULL, 
	run_id VARCHAR(36) NOT NULL, 
	platform VARCHAR(32) NOT NULL, 
	platform_post_id VARCHAR(128), 
	published_url VARCHAR(512), 
	output_path VARCHAR(512), 
	published_at DATETIME, 
	content TEXT NOT NULL, 
	hashtags TEXT, 
	internal_links TEXT, 
	media_urls TEXT, 
	creative_angle TEXT, 
	qa_safety_passed BOOLEAN, 
	qa_re_relevance FLOAT, 
	qa_backlink_score FLOAT, 
	qa_brand_voice FLOAT, 
	qa_overall FLOAT, 
	pred_impressions INTEGER, 
	pred_likes INTEGER, 
	pred_shares INTEGER, 
	pred_comments INTEGER, 
	pred_ctr FLOAT, 
	pred_engagement_rate FLOAT, 
	pred_confidence FLOAT, 
	actual_impressions_6h INTEGER, 
	actual_likes_6h INTEGER, 
	actual_impressions_24h INTEGER, 
	actual_likes_24h INTEGER, 
	actual_shares_24h INTEGER, 
	actual_comments_24h INTEGER, 
	actual_ctr_24h FLOAT, 
	actual_saves_24h INTEGER, 
	actual_impressions_7d INTEGER, 
	actual_engagement_7d FLOAT, 
	actual_housing_traffic INTEGER, 
	prediction_accuracy FLOAT, user_rating INTEGER, user_tags TEXT, user_feedback TEXT, user_action VARCHAR(32), rejection_reason TEXT, draft_type VARCHAR(16), zomato_hook TEXT, trend_hashtag VARCHAR(128), media_format VARCHAR(32), qa_decision VARCHAR(32), post_status VARCHAR(32), qa_rejection_reasons TEXT, source_topic TEXT, qa_critique TEXT, qa_quality_dimensions TEXT, engagement_reasoning TEXT, trend_data TEXT, extra_data TEXT, image_cloud_url TEXT, 
	PRIMARY KEY (id)
);
CREATE INDEX ix_published_posts_platform ON published_posts (platform);
CREATE UNIQUE INDEX ix_published_posts_post_id ON published_posts (post_id);
CREATE INDEX ix_published_posts_run_id ON published_posts (run_id);
CREATE TABLE runs (
	id INTEGER NOT NULL, 
	run_id VARCHAR(36) NOT NULL, 
	status VARCHAR(32) NOT NULL, 
	triggered_at DATETIME, 
	completed_at DATETIME, 
	dry_run BOOLEAN, 
	topic_hint TEXT, 
	target_platforms TEXT, 
	research_count INTEGER, 
	trends_count INTEGER, 
	briefs_count INTEGER, 
	drafts_count INTEGER, 
	posts_attempted INTEGER, 
	posts_approved INTEGER, 
	posts_published INTEGER, 
	error TEXT, 
	summary_json TEXT, 
	PRIMARY KEY (id)
);
CREATE UNIQUE INDEX ix_runs_run_id ON runs (run_id);
CREATE TABLE llm_calls (
	id INTEGER NOT NULL, 
	run_id VARCHAR(36), 
	called_at DATETIME, 
	agent VARCHAR(128), 
	model VARCHAR(64), 
	system_prompt TEXT, 
	user_message TEXT, 
	response_text TEXT, 
	stop_reason VARCHAR(32), 
	input_tokens INTEGER, 
	output_tokens INTEGER, 
	cost_usd FLOAT, 
	elapsed_ms INTEGER, 
	PRIMARY KEY (id)
);
CREATE INDEX ix_llm_calls_run_id ON llm_calls (run_id);
CREATE TABLE api_calls (
	id INTEGER NOT NULL, 
	run_id VARCHAR(36), 
	called_at DATETIME, 
	agent VARCHAR(64), 
	api_name VARCHAR(64), 
	endpoint VARCHAR(512), 
	params_json TEXT, 
	response_json TEXT, 
	result_count INTEGER, 
	status VARCHAR(16), 
	http_status INTEGER, 
	error TEXT, 
	elapsed_ms INTEGER, 
	use_case TEXT, 
	PRIMARY KEY (id)
);
CREATE INDEX ix_api_calls_run_id ON api_calls (run_id);

