INSERT INTO published_posts VALUES(18,'29407804-bf56-41be-acb2-567ac5cfd9e1','f44d16a3','youtube','dry_run_29407804','dry_run','output/f44d16a3/youtube_post.md','2026-05-17 20:01:53.537683',replace('[HOOK] Bengaluru homeowners — the government just slashed your property conversion fee. Here''s what you need to know RIGHT NOW.\n[BODY] Under Karnataka''s Bhoo Guarantee scheme, the B-Khata to A-Khata conversion fee has been cut to just 2%. This unlocks 23 lakh properties across Bengaluru — making them eligible for loans, legal transactions, and proper civic services. But here''s the catch — you only have a 100-day window to grab this reduced rate. Miss it, and you pay full price.\n[CTA] Follow Housing.com for more Bengaluru property updates. Link in bio to explore properties now.\n\nLONG-FORM TITLE: B-Khata to A-Khata: Fee Cut to 2% — Bengaluru''s 100-Day Window Explained','\n',char(10)),'["B-Khata to A-Khata", "Karnataka Bhoo Guarantee Scheme", "Bengaluru property news 2024", "A-Khata conversion fee", "BBMP Khata conversion", "Bengaluru real estate", "B-Khata properties Bengaluru", "Karnataka property registration", "Khata conversion 2%", "Bengaluru homeowners", "BBMP A-Khata benefits", "Karnataka government scheme", "property conversion Bengaluru", "housing news India", "Housing.com"]','[{"url": "https://housing.com/in/buy/real-estate-mumbai", "anchor_text": "Properties in Mumbai", "page_type": "city_homepage", "city": "mumbai"}, {"url": "https://housing.com/in/buy/real-estate-bengaluru", "anchor_text": "Properties in Bengaluru", "page_type": "city_homepage", "city": "bengaluru"}]','[]','Bengaluru B-Khata to A-Khata conversion fee slashed to 2% — directly tied to a real, time-bound civic win that unlocks 23 lakh properties. Pure utility + urgency play for Bengaluru audience.',1,9.199999999999999289,4.5,5.5,6.900000000000000355,18000,540,95,70,0.07199999999999999455,0.05079999999999999794,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NUL