INSERT INTO published_posts VALUES(19,'a268ce08-ac3c-491b-bc93-fcd4d6e54b18','f44d16a3','instagram','dry_run_a268ce08','dry_run','output/f44d16a3/instagram_post.md','2026-05-17 20:01:53.540160',replace('**REVISED INSTAGRAM POST**\n\n---\n\nReels se aura nahi aata, registry se aata hai 🔑\n\nSach mein — apna ghar hona India ka biggest flex hai, aur abhi time bhi sahi hai:\n✅ 6 lakh+ new homes listed across top cities\n✅ PMAY 3.0 subsidies still available for first-time buyers\n✅ Verified, RERA-registered properties only — no stress, no scams\n\nApna next (real) flex dhundho 👇\nMumbai mein 2BHK under ₹50L dekho: housing.com/in/buy/real-estate-mumbai\nBengaluru mein options explore karo: housing.com/in/buy/real-estate-bengaluru\n\n*Note: Always verify RERA registration before booking any property. Your aura — and your savings — deserve that protection. 🏠*\n\n---\n\n**HASHTAGS:**\n#AuraFarming #GharWalaFlex #HousingDotCom #GharKhojna #GenZIndia #HomeOwner #RealEstateIndia #ApnaGhar #GharKaSapna #PropertyIndia #HomeBuying #RERAVerified #FirstTimeBuyer #PMAY #DesiMemes #IndianGenZ #SmartHomeBuying #AuraPoints','\n',char(10)),'["#AuraFarming", "#AuraFarm", "#GharWalaFlex", "#HousingDotCom", "#GharKhojna", "#AuraCheck", "#GenZIndia", "#HomeOwner", "#RealEstateIndia", "#ApnaGhar", "#ViralTrend", "#IndianGenZ", "#GharKaSapna", "#PropertyIndia", "#HomeBuying", "#AuraPoints", "#DesiMemes", "#InstagramIndia"]','[{"url": "https://housing.com/in/buy/real-estate-mumbai", "anchor_text": "Properties in Mumbai", "page_type": "city_homepage", "city": "mumbai"}, {"url": "https://housing.com/in/buy/real-estate-bengaluru", "anchor_text": "Properties in Bengaluru", "page_type": "city_homepage", "city": "bengaluru"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f44d16a3/instagram_a1f3c9e2.png"]','Aura farming meme — the ultimate aura flex is owning a home, not posting reels. Connects Gen Z viral slang to homeowner pride.',1,7.5,3.0,7.0,5.400000000000000355,45000,