INSERT INTO published_posts VALUES(149,'1ab4d094-860d-433d-a400-f859104db0bb','6b20ed42','twitter','','','output/6b20ed42/rejected/twitter_1ab4d094.md','2026-05-18 20:21:06.608224',replace('40k rent, ek pankha, ek prayer 🙏\n\nMumbai ka EMI usse sasta padega — aur ghar bhi apna hoga.\n\nMummy ke ghar wapas jaane se pehle ek baar dekh lo 👉 housing.com/in/buy/mumbai','\n',char(10)),'["#StandUpComedy", "#MumbaiRent", "#RentVsBuy", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/mumbai", "anchor_text": "mumbai", "page_type": "city_srp", "placement": "tweet"}]','[]','Stand-up bit: ''moved back to parents after rent hike'' — flip into home loan EMI being cheaper than Mumbai rent. Ownership as the real punchline.',1,0.0,8.0,0.0,6.099999999999999645,18500,285,95,142,2.799999999999999823,3.200000000000000177,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('40k rent, ek pankha, ek prayer 🙏\nUtne mein toh EMI nikal jaaye, aur ghar bhi apna ho jaaye 🏠','\n',char(10)),'#StandUpComedy','branded_card','revise','qa_rejected','["trend_dominance", "Improve: No real-world trend hook\u2014''stand-up comedy'' reference is vague and not tied to a specific viral moment, comedian, or current meme. Reduces shareability and viral potential significantly."]','kunal kamra',NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO published_posts VALUES(150,'73ab2070-b03c-4000-ac85-94e3ea2b4b48','8b980603','twitter','dry_run_73ab2070','dry_run','output/8b980603/published/twitter_73ab2070.md','2026-05-18 20:26:56.329053',replace('ChatGPT ne bhi Dilli choose kiya 🤖\n\nAI bhi jaanta hai — location matters.\n\n@OpenAI ka first India office = New Delhi certified.\n\nTu abhi bhi soch raha hai? housing.com/in/buy/new-delhi','\n',char(10)),'["#OpenAIIndia", "#DelhiNCR"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "delhi", "page_type": "city_srp", "placement": "tweet"}]','[]','OpenAI choosing Delhi for its first India office = ultimate validation for Delhi NCR real estate. Even AI knows Dilli dil walon ka hai.',1,0.0,9.0,0.0,8.0,18500,142,28,35,2.100000000000000088,1.399999999999999912,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('ChatGPT ne bhi Dilli choose kiya 🤖\nAur tu abhi bhi soch raha hai? 🏠','\n',char(10)),'#OpenAIIndia','branded_card','publish','published','[]','BREAKING: OpenAI Launches $10B Deployment Giant - YouTube','This is a solid trend-jack — the OpenAI India office news is the clear hero, and ''ChatGPT ne bhi Dilli choose kiya'' is a genuinely witty opener that earns its place. The pivot ''AI bhi jaanta hai — location matters'' is clean and doesn''t feel forced. However, the middle line ''@OpenAI ka first India office = New Delhi certified'' is slightly redundant — it restates the hook rather than adding a new layer of wit or surprise, which flattens the momentum before the CTA. Compare to the Ghibli AI approved example: ''Housing.com tumhara address badlega — that''s the real glow-up'' — that pivot has a sharper sting. Here, ''Tu abhi bhi soch raha hai?'' is good but slightly predictable as a closer; it doesn''t land with the same unexpected twist that would push this from shareable to quote-tweet-worthy. One emoji is well-used and within limits. No corporate speak. Overall this matches the approved examples in craft but doesn''t clearly surpass them.','{"character_compliance": 10.0, "trend_dominance": 8.0, "shareability": 7.5, "hinglish_wit": 7.5, "cta_quality": 9.0}','Strong hook leveraging OpenAI''s India expansion news (timely trend) with witty personification of AI choosing Delhi. Clever wordplay (''AI bhi jaanta hai'') creates curiosity and aspiration. However, engagement is capped by: (1) No visual asset (image/video) — critical miss for Twitter real estate content, (2) Indirect CTA (link in bio style) reduces click friction but weakens urgency, (3) Niche appeal — only resonates with Delhi property seekers + tech-savvy audience, not broad Housing.com base. The ''Tu abhi bhi soch raha hai?'' creates mild FOMO but lacks emotional punch. Hashtags are relevant but #DelhiNCR is generic. Predicted 1.4% ER is solid (above 0.8% benchmark) but below 2-4% ''good'' threshold due to missing visual and softer CTA.','{"hashtag": "#OpenAIIndia", "volume": "high", "platform": "twitter", "context": "OpenAI is opening its first India office in New Delhi by end of 2025, signaling massive AI investment in the country.", "creative_hook": "OpenAI chose New Delhi for its first India office. Coincidence? No. Delhi real estate just got its biggest flex yet. If AI giants are betting on Delhi NCR, maybe it''s time YOU did too. \ud83d\udc40\ud83c\udfe0 #OpenAIIndia #DelhiNCR", "city_hint": "Delhi", "tags": ["tech", "ai", "delhi", "infrastructure", "investment"]}',NULL,NULL);
INSERT INTO published_posts VALUES(151,'361445f8-badc-42a2-a58a-2b508e732d3c','8b980603','instagram','dry_run_361445f8','dry_run','output/8b980603/published/instagram_361445f8.md','2026-05-18 20:26:56.332440','ChatGPT ne bhi Dilli choose kiya 🤖 AI ko pata hai sahi jagah kaunsi hai — ab tera number hai! 🏠 housing.com/in/buy/new-delhi','["#OpenAIIndia", "#HousingDotCom", "#GharKhojna", "#DelhiNCR", "#DelhiRealEstate", "#AIinIndia", "#DilliDilWalonKa", "#NewDelhi", "#DelhiHomes", "#GharLo", "#OpenAI", "#DelhiLife", "#IndiaAI", "#PropertyInDelhi", "#GharKaSapna", "#RealEstateIndia", "#DelhiLiving"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "delhi", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/8b980603/instagram_a3f8c2d1.png"]','OpenAI choosing Delhi for its first India office = ultimate validation for Delhi NCR real estate. Even AI knows Dilli dil walon ka hai.',1,0.0,0.0,0.0,6.5,45000,1080,225,315,2.799999999999999823,2.399999999999999912,0.6199999999999999956,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('ChatGPT ne bhi Dilli choose kiya 🤖\nAur tu abhi bhi soch raha hai? 🏠','\n',char(10)),'#OpenAIIndia','branded_card','publish','published','[]','BREAKING: OpenAI Launches $10B Deployment Giant - YouTube','The card concept has the right instincts — using OpenAI/ChatGPT as a cultural hook to validate Delhi is clever and on-trend. But the execution is slightly surface-level. ''ChatGPT ne bhi Dilli choose kiya'' is a fun premise, but it doesn''t land with a sharp enough punchline — the second line ''Aur tu abhi bhi soch raha hai?'' is a generic nudge that any brand could write. Compare to the approved ''Kejriwal jaaye ya aaye, Delhiwalon ko ghar toh chahiye hi'' — that card has a self-contained wit that works even without the housing angle. This card''s hook depends entirely on the reader knowing the OpenAI-India news, and the payoff (''ab tera number hai'') in the caption is a mild kicker rather than a punchy close. The caption at ~85 chars is within limit and Hinglish is present, but ''ab tera number hai'' feels like a filler phrase rather than a genuine emotional or humorous closer. Hashtag order is correct with #OpenAIIndia first, and count (17) is within range.','{"card_hook_strength": 6.5, "trend_and_shareability": 6.0, "caption_punch": 6.5, "hashtag_strategy": 7.5}','Strong hook leveraging the #OpenAIIndia trend (currently fresh & high-volume search), but engagement is capped by: (1) Trend relevance declining post-announcement week, (2) Humour is light-touch, not laugh-out-loud, (3) CTA is indirect (link-only, no urgency), (4) Audience overlap between AI enthusiasts and active property hunters is moderate. The ''Aur tu abhi bhi soch raha hai?'' creates mild FOMO but doesn''t trigger immediate action. Hashtag density (17 tags) is strong for reach but dilutes focus. Branded card format performs 15-20% below video/carousel on Instagram.','{"hashtag": "#OpenAIIndia", "volume": "high", "platform": "twitter", "context": "OpenAI is opening its first India office in New Delhi by end of 2025, signaling massive AI investment in the country.", "creative_hook": "OpenAI chose New Delhi for its first India office. Coincidence? No. Delhi real estate just got its biggest flex yet. If AI giants are betting on Delhi NCR, maybe it''s time YOU did too. \ud83d\udc40\ud83c\udfe0 #OpenAIIndia #DelhiNCR", "city_hint": "Delhi", "tags": ["tech", "ai", "delhi", "infrastructure", "investment"]}',NULL,'https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/8b980603/instagram_a3f8c2d1.png');
INSERT INTO published_posts VALUES(152,'5b8a10dd-0d02-4ca3-9935-6cdd3ecffdc4','8b980603','twitter','dry_run_5b8a10dd','dry_run','output/8b980603/published/twitter_5b8a10dd.md','2026-05-18 20:26:56.334002',replace('AI tera kaam le legi 🤖\nLekin ghar? Woh tu khud lega 🔑\n\nNoida-Gurugram mein settle ho ja, AI se pehle 😏\n\nhttps://housing.com/in/buy/noida','\n',char(10)),'["#AIJobs", "#Noida", "#Gurugram", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/noida", "anchor_text": "noida", "page_type": "city_srp", "placement": "tweet"}]','[]','AI jobs surge in Noida-Gurugram means new tech professionals will need homes. Career level up = ghar level up.',1,0.0,7.0,0.0,6.099999999999999645,28500,198,89,142,3.200000000000000177,2.100000000000000088,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('AI tera kaam le legi 🤖\nLekin ghar? Woh tu khud lega 🔑','\n',char(10)),'#AIJobs','branded_card','publish','published','[]','BREAKING: OpenAI Launches $10B Deployment Giant - YouTube','The opening couplet — ''AI tera kaam le legi / Lekin ghar? Woh tu khud lega'' — is genuinely witty and lands the existential AI anxiety in a relatable way. That''s the strongest part. But the post loses its footing in the second half: ''150+ AI roles, @OpenAI India wave incoming. Salary aane se pehle Noida-Gurugram mein lock karo.'' This pivot turns the tweet into a housing promo wearing an AI costume. The trend hook (AI job anxiety) is sharp, but the body copy abandons the emotional resonance and pivots to a transactional real estate pitch — ''salary aane se pehle lock karo'' reads like a sales nudge, not a cultural observation. Compared to the approved examples (e.g., the pollution PM quitting joke, where the housing CTA is a single soft line at the end), this post gives too much real estate weight to the second half, making Housing the co-star rather than the punchline. The trend stops being dominant after line 2. Also, ''150+ AI roles'' is a data claim that needs sourcing — if unverified, it''s a false claim risk.','{"character_compliance": 10.0, "trend_dominance": 5.5, "shareability": 6.0, "hinglish_wit": 6.5, "cta_quality": 7.0}','Strong hook with Hindi-English wordplay (''AI tera kaam le legi'' vs ''ghar tu khud lega'') creates immediate curiosity and relatability for urban Indian audience. Timely relevance: OpenAI India expansion + AI job boom is trending. Emotional drivers: aspiration (high-paying AI roles) + FOMO (lock property before salary influx) + humour (witty contrast). CTA is clear but could be more direct. Hashtags are relevant but generic. No visual asset limits viral potential. Estimated 2.1% engagement sits in ''Good'' range (2-4%), not viral, due to lack of image and somewhat niche appeal (AI professionals in NCR).','{"hashtag": "#AIJobs", "volume": "high", "platform": "instagram", "context": "OpenAI''s India expansion and $10B deployment push is expected to create a massive wave of high-paying AI jobs across Indian metros.", "creative_hook": "OpenAI aa raha hai India. \ud83d\udcb8 ~150 AI specialists. New Delhi office. $20B revenue target. Bhai, jab itni AI salaries aayengi, Noida-Gurugram flats ka kya hoga? Spoiler: UP hi UP hoga. \ud83d\udcc8\ud83c\udfe2 Start house hunting before your next appraisal. #AIJobs #Noida #Gurugram", "city_hint": "Noida", "tags": ["ai", "tech", "jobs", "noida", "delhi", "investment", "infrastructure"]}',NULL,NULL);
INSERT INTO published_posts VALUES(153,'a89c76c8-c64c-4494-a7e7-5ef27ea107ed','8b980603','instagram','dry_run_a89c76c8','dry_run','output/8b980603/published/instagram_a89c76c8.md','2026-05-18 20:26:56.335883','AI jobs aa rahe, ghar lock karo pehle 🔑 Noida-Gurugram mein salary se pehle address pakdo 👉 housing.com/in/buy/noida','["#AIJobs", "#HousingDotCom", "#GharKhojna", "#Noida", "#Gurugram", "#OpenAI", "#TechJobs", "#NCR", "#NoidaRealEstate", "#GurgaonLife", "#TechProfessionals", "#NewHome", "#CareerLevelUp", "#GharLevelUp", "#PropTech", "#HomeBuying", "#DelhiNCR"]','[{"url": "https://housing.com/in/buy/noida", "anchor_text": "noida", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/8b980603/instagram_b4e9d3c2.png"]','AI jobs surge in Noida-Gurugram means new tech professionals will need homes. Career level up = ghar level up.',1,0.0,0.0,0.0,7.200000000000000177,45000,2100,380,520,8.400000000000000355,7.200000000000000177,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('AI tera kaam le legi 🤖\nLekin ghar? Woh tu khud lega 🔑','\n',char(10)),'#AIJobs','branded_card','publish','published','[]','BREAKING: OpenAI Launches $10B Deployment Giant - YouTube','The card text ''AI tera kaam le legi 🤖 Lekin ghar? Woh tu khud lega 🔑'' is a genuinely clever pivot — the contrast between AI taking your job and you still having to earn your home is a real cultural tension that GenZ will feel. It matches the approved examples in Hinglish craft and is close to a 7-8 anchor. However, it doesn''t quite surpass them: the ''AI takes jobs'' angle is already a well-worn meme format, so the surprise factor is moderate rather than sharp. The caption ''AI jobs aa rahe, ghar lock karo pehle 🔑 Noida-Gurugram mein salary se pehle address pakdo'' is punchy and under 150 chars — ''salary se pehle address pakdo'' is the strongest line in the whole post and does close the card well. The main drag is hashtag strategy: #AIJobs is listed first (correct), but the set has only 17 tags (within range), yet includes filler tags like #TechProfessionals and #PropTech that dilute reach without adding trend signal. More critically, obvious high-reach tags like #ArtificialIntelligence, #AIIndia, or #TechLayoffs — which would ride the actual trending conversation — are missing, weakening discoverability.','{"card_hook_strength": 7.5, "trend_and_shareability": 7.0, "caption_punch": 7.5, "hashtag_strategy": 6.5}','Strong hook leveraging trending #AIJobs topic with humorous Hinglish wordplay (''AI tera kaam le legi'' vs ''ghar tu khud lega''). High relevance to NCR tech professionals experiencing salary growth and housing demand. Emotional drivers: aspiration (career growth), FOMO (AI boom), and light humour. Clear CTA with direct link. Hashtag strategy targets both tech and real estate audiences. Branded card format is clean and scroll-stopping. Confidence slightly moderated due to: (1) Hinglish may limit reach outside Hindi-speaking regions, (2) Real estate CTAs typically underperform vs. lifestyle content, (3) Meme concept is clever but not viral-tier originality.','{"hashtag": "#AIJobs", "volume": "high", "platform": "instagram", "context": "OpenAI''s India expansion and $10B deployment push is expected to create a massive wave of high-paying AI jobs across Indian metros.", "creative_hook": "OpenAI aa raha hai India. \ud83d\udcb8 ~150 AI specialists. New Delhi office. $20B revenue target. Bhai, jab itni AI salaries aayengi, Noida-Gurugram flats ka kya hoga? Spoiler: UP hi UP hoga. \ud83d\udcc8\ud83c\udfe2 Start house hunting before your next appraisal. #AIJobs #Noida #Gurugram", "city_hint": "Noida", "tags": ["ai", "tech", "jobs", "noida", "delhi", "investment", "infrastructure"]}',NULL,'https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/8b980603/instagram_b4e9d3c2.png');
INSERT INTO published_posts VALUES(154,'cb802c59-0fee-4d88-93e3-cbdcb68c471c','8b980603','twitter','dry_run_cb802c59','dry_run','output/8b980603/published/twitter_cb802c59.md','2026-05-18 20:26:56.337947',replace('ChatGPT ne bhi Dilli choose kiya 🤖\n\nAI ne location final kar liya — tu abhi bhi soch raha hai?\n\n@OpenAI ka first India office = Delhi NCR ka ultimate validation.\n\nGhar dhundh: https://housing.com/in/buy/new-delhi','\n',char(10)),'["#OpenAIIndia", "#DelhiNCR", "#GharKhojna"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "delhi", "page_type": "city_srp", "placement": "tweet"}]','[]','OpenAI choosing Delhi for its first India office = ultimate validation for Delhi NCR real estate. Even AI knows Dilli dil walon ka hai.',1,0.0,8.0,0.0,7.5,18500,215,89,127,3.200000000000000177,2.100000000000000088,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('ChatGPT ne bhi Dilli choose kiya 🤖\nAur tu abhi bhi soch raha hai? 🏠','\n',char(10)),'#OpenAIIndia','branded_card','publish','published','[]','BREAKING: OpenAI Launches $10B Deployment Giant - YouTube','The post rides the OpenAI India office announcement well — ''ChatGPT ne bhi Dilli choose kiya'' is a genuinely sharp opener that earns attention. The pivot ''AI ne location final kar liya — tu abhi bhi soch raha hai?'' is clever and the housing connection feels earned rather than bolted on. However, the third line ''@OpenAI ka first India office = Delhi NCR ka ultimate validation'' slightly over-explains the joke and tips the balance toward housing promo territory — the trend hook is strongest in line 1, but by line 3 it''s being used as a real estate argument rather than staying as the cultural punchline. Compare to the Ghibli AI approved example: ''Housing.com tumhara address badlega — that''s the real glow-up'' — the housing pivot lands in one punchy line without needing to justify itself with data. Here, ''ultimate validation'' reads slightly like a marketing claim. The emoji count (1) is fine. Hinglish is natural but the post could be tighter — three lines of setup before the CTA makes it feel slightly long for Twitter''s scroll speed.','{"character_compliance": 10.0, "trend_dominance": 7.5, "shareability": 7.0, "hinglish_wit": 7.0, "cta_quality": 8.0}','Strong hook leveraging OpenAI''s India office announcement (trending topic) with witty comparison (''AI ne location final kar liya — tu abhi bhi soch raha hai?''). Bilingual wordplay and FOMO/aspiration angle resonate well with Delhi NCR property seekers. Direct CTA with link is clear. However, lacks visual asset (no image) which typically boosts engagement by 30-40% on Twitter. Confidence slightly tempered by absence of media and reliance on trend freshness (OpenAI announcement timing critical). Hashtags are relevant but generic.','{"hashtag": "#OpenAIIndia", "volume": "high", "platform": "twitter", "context": "OpenAI is opening its first India office in New Delhi by end of 2025, signaling massive AI investment in the country.", "creative_hook": "OpenAI chose New Delhi for its first India office. Coincidence? No. Delhi real estate just got its biggest flex yet. If AI giants are betting on Delhi NCR, maybe it''s time YOU did too. \ud83d\udc40\ud83c\udfe0 #OpenAIIndia #DelhiNCR", "city_hint": "Delhi", "tags": ["tech", "ai", "delhi", "infrastructure", "investment"]}',NULL,NULL);
INSERT INTO published_posts VALUES(155,'4d5016d8-2672-4bd3-b201-d8dd969a321a','8b980603','instagram','dry_run_4d5016d8','dry_run','output/8b980603/published/instagram_4d5016d8.md','2026-05-18 20:26:56.339277','ChatGPT ne Dilli choose kiya 🤖 AI ka sense tujhse better hai kya? Apna ghar dhundh ab 👉 housing.com/in/buy/new-delhi','["#OpenAIIndia", "#HousingDotCom", "#GharKhojna", "#DelhiNCR", "#DelhiRealEstate", "#AIinIndia", "#DilliDilWaloKi", "#NewDelhi", "#DelhiHomes", "#GharDhundho", "#RealEstateIndia", "#HomeBuying", "#DelhiLife", "#PropTech", "#SmartCity", "#IndiaAI", "#LocationLocation"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "delhi", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/8b980603/instagram_a3f8c2d1.png"]','OpenAI choosing Delhi for its first India office = ultimate validation for Delhi NCR real estate. Even AI knows Dilli dil walon ka hai.',1,0.0,0.0,0.0,6.200000000000000177,45000,1890,315,405,4.200000000000000177,4.200000000000000177,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('ChatGPT ne bhi Dilli choose kiya 🤖\nAur tu abhi bhi soch raha hai? 🏠','\n',char(10)),'#OpenAIIndia','branded_card','publish','published','[]','BREAKING: OpenAI Launches $10B Deployment Giant - YouTube','The card concept is directionally right — AI trend-jacking with a Hinglish punchline is a valid play — but ''ChatGPT ne bhi Dilli choose kiya'' leans on a premise that isn''t grounded in any real news or viral moment, making it feel manufactured rather than trend-native. Compare to the approved ''Kejriwal jaaye ya aaye'' card, which anchors to a real, emotionally charged event — this one floats. The second line ''Aur tu abhi bhi soch raha hai?'' is a decent kicker but generic; it could apply to any product decision. The caption is the bigger problem: ''ChatGPT ne Dilli choose kiya 🤖 AI ka sense tujhse better hai kya? Apna ghar dhundh ab 👉 housing.com/in/buy/new-delhi'' — the card and caption are essentially saying the same thing twice, which wastes the caption''s job as a closer. ''Apna ghar dhundh ab'' is a flat, directive CTA that reads like a bolted-on promo line (exactly the failure pattern flagged). The AI-to-housing pivot also lacks a logical bridge — why does ChatGPT choosing Delhi mean you should buy there? The wit doesn''t land because the premise doesn''t hold. Hashtag order is correct (#OpenAIIndia first) and count is within range.','{"card_hook_strength": 6.5, "trend_and_shareability": 6.0, "caption_punch": 5.5, "hashtag_strategy": 7.5}','Strong hook leveraging #OpenAIIndia trend (currently fresh in India discourse) with playful AI-human comparison creates curiosity & light humour. Hinglish copy resonates with Delhi metro audience. FOMO element (''aur tu abhi bhi soch raha hai?'') drives engagement. However, CTA is slightly indirect (link in caption vs. swipe-up), and the meme concept lacks visual punch—relying on text-heavy branded card format. Relevance is high but trend momentum may fade within 48-72 hours. Hashtag strategy is solid (mix of trending + niche), supporting 4-5% engagement for Housing.com''s 200K baseline.','{"hashtag": "#OpenAIIndia", "volume": "high", "platform": "twitter", "context": "OpenAI is opening its first India office in New Delhi by end of 2025, signaling massive AI investment in the country.", "creative_hook": "OpenAI chose New Delhi for its first India office. Coincidence? No. Delhi real estate just got its biggest flex yet. If AI giants are betting on Delhi NCR, maybe it''s time YOU did too. \ud83d\udc40\ud83c\udfe0 #OpenAIIndia #DelhiNCR", "city_hint": "Delhi", "tags": ["tech", "ai", "delhi", "infrastructure", "investment"]}',NULL,'https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/8b980603/instagram_a3f8c2d1.png');
INSERT INTO published_posts VALUES(156,'9f6fd61a-b6a1-4e50-a850-aab3a3af4e6b','8b980603','twitter','dry_run_9f6fd61a','dry_run','output/8b980603/published/twitter_9f6fd61a.md','2026-05-18 20:26:56.340413',replace('AI tera kaam le legi 🤖\nLekin ghar? Woh tu khud lega 🔑\n\n150+ AI jobs, @OpenAI India wave incoming. Salary aane se pehle Noida-Gurugram mein lock karo.\n\nhttps://housing.com/in/buy/noida','\n',char(10)),'["#AIJobs", "#Noida", "#Gurugram", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/noida", "anchor_text": "noida", "page_type": "city_srp", "placement": "tweet"}]','[]','AI jobs surge in Noida-Gurugram means new tech professionals will need homes. Career level up = ghar level up.',1,0.0,8.0,0.0,7.599999999999999645,28500,198,89,142,3.200000000000000177,2.100000000000000088,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('AI tera kaam le legi 🤖\nLekin ghar? Woh tu khud lega 🔑','\n',char(10)),'#AIJobs','branded_card','publish','published','[]','BREAKING: OpenAI Launches $10B Deployment Giant - YouTube','The opening couplet — ''AI tera kaam le legi / Lekin ghar? Woh tu khud lega'' — is genuinely sharp and earns its place; the contrast between AI displacement anxiety and human agency over homeownership is a clever pivot. However, the second half (''150+ AI jobs, @OpenAI India wave incoming. Salary aane se pehle Noida-Gurugram mein lock karo.'') shifts the register from witty cultural commentary to a fairly transactional pitch, which slightly undercuts the wit established in line one. The phrase ''Salary aane se pehle lock karo'' is a reasonable punchline but leans more promotional than the approved examples, which tend to let the housing angle emerge more organically rather than spelling out the financial logic. Compared to the approved examples (which anchor at 7-8), this post matches that tier — the trend hook is present and dominant, the Hinglish voice is natural, but the second half is slightly more ''ad-like'' than the best approved examples. No hard failures, but the transition from wit to pitch is a touch abrupt.','{"character_compliance": 10.0, "trend_dominance": 7.5, "shareability": 7.0, "hinglish_wit": 7.5, "cta_quality": 8.0}','Strong hook with Hindi-English wordplay (''AI tera kaam le legi'' vs ''ghar tu khud lega'') creates immediate curiosity and relatability. Taps into timely trend (OpenAI India expansion + AI job boom) with FOMO angle. Aspiration driver (salary → property) resonates with target demographic (young professionals in NCR). Clear CTA with direct link. Weakness: No visual asset (image/video) limits scroll-stopping power on Twitter; lacks specific salary/job details that could amplify urgency.','{"hashtag": "#AIJobs", "volume": "high", "platform": "instagram", "context": "OpenAI''s India expansion and $10B deployment push is expected to create a massive wave of high-paying AI jobs across Indian metros.", "creative_hook": "OpenAI aa raha hai India. \ud83d\udcb8 ~150 AI specialists. New Delhi office. $20B revenue target. Bhai, jab itni AI salaries aayengi, Noida-Gurugram flats ka kya hoga? Spoiler: UP hi UP hoga. \ud83d\udcc8\ud83c\udfe2 Start house hunting before your next appraisal. #AIJobs #Noida #Gurugram", "city_hint": "Noida", "tags": ["ai", "tech", "jobs", "noida", "delhi", "investment", "infrastructure"]}',NULL,NULL);
INSERT INTO published_posts VALUES(157,'506ed84f-03e6-491e-af65-2081d54494de','8b980603','instagram','dry_run_506ed84f','dry_run','output/8b980603/published/instagram_506ed84f.md','2026-05-18 20:26:56.341929','AI jobs aa rahe, salary aane se pehle ghar lock karo 🔑 Career level up = ghar level up 👉 housing.com/in/buy/noida @openai','["#AIJobs", "#HousingDotCom", "#GharKhojna", "#Noida", "#Gurugram", "#TechJobs", "#OpenAI", "#NCR", "#NoidaRealEstate", "#GurgaonLife", "#TechProfessionals", "#NewHome", "#PropTech", "#GharMilega", "#CareerLevelUp", "#NoidaHomes", "#AIIndia", "#HomeBuying"]','[{"url": "https://housing.com/in/buy/noida", "anchor_text": "noida", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/8b980603/instagram_b4e9d3c2.png"]','AI jobs surge in Noida-Gurugram means new tech professionals will need homes. Career level up = ghar level up.',1,0.0,0.0,0.0,7.099999999999999645,45000,2100,380,520,8.400000000000000355,7.200000000000000177,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('AI tera kaam le legi 🤖\nLekin ghar? Woh tu khud lega 🔑','\n',char(10)),'#AIJobs','branded_card','publish','published','[]','BREAKING: OpenAI Launches $10B Deployment Giant - YouTube','The card text ''AI tera kaam le legi 🤖 Lekin ghar? Woh tu khud lega 🔑'' is genuinely punchy — the contrast between AI taking your job and you owning your home is a clean, witty pivot that earns its scroll-stop. It matches the approved examples in craft. However, the caption ''AI jobs aa rahe, salary aane se pehle ghar lock karo 🔑 Career level up = ghar level up 👉 housing.com/in/buy/noida @openai'' slightly dilutes the card''s wit by restating the same idea less elegantly — ''Career level up = ghar level up'' is a flat equation that doesn''t land as a kicker. The @openai tag feels like a reach for clout rather than an organic cultural tie. The card and caption don''t feel fully designed as a unit — the card opens with existential AI humour, but the caption pivots to career aspiration, breaking the tonal thread. Hashtag order is correct (#AIJobs first), count is 18 (within range), and branded tags are present.','{"card_hook_strength": 7.5, "trend_and_shareability": 7.0, "caption_punch": 6.5, "hashtag_strategy": 7.0}','Strong hook leveraging AI job anxiety + aspirational home ownership narrative. Hinglish copy resonates with NCR tech professionals (core Housing.com audience). Timely trend alignment (#AIJobs trending in India). Emotional trigger: FOMO + aspiration (career growth = lifestyle upgrade). Clear CTA with direct link. Branded card format performs well on Instagram. Weakness: Slightly cynical tone (''AI tera kaam le legi'') may alienate some, and the connection between AI jobs → Noida homes feels forced rather than organic. Hashtag density is high (16 tags) which is acceptable but risks looking spammy.','{"hashtag": "#AIJobs", "volume": "high", "platform": "instagram", "context": "OpenAI''s India expansion and $10B deployment push is expected to create a massive wave of high-paying AI jobs across Indian metros.", "creative_hook": "OpenAI aa raha hai India. \ud83d\udcb8 ~150 AI specialists. New Delhi office. $20B revenue target. Bhai, jab itni AI salaries aayengi, Noida-Gurugram flats ka kya hoga? Spoiler: UP hi UP hoga. \ud83d\udcc8\ud83c\udfe2 Start house hunting before your next appraisal. #AIJobs #Noida #Gurugram", "city_hint": "Noida", "tags": ["ai", "tech", "jobs", "noida", "delhi", "investment", "infrastructure"]}',NULL,'https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/8b980603/instagram_b4e9d3c2.png');
INSERT INTO published_posts VALUES(158,'4de7e4ed-c74f-4e21-a552-9cbc401fa827','f07be5c1','twitter','dry_run_4de7e4ed','dry_run','output/f07be5c1/published/twitter_4de7e4ed.md','2026-05-19 02:21:40.860462',replace('Baghban rewatch hitting different when you realize the REAL solution was a builder floor 😭\n\nDada ke liye ground floor 🪑\nBeta ke liye first floor\nPote ke liye terrace pe future 🌟\n\nEk ghar, teen generations, zero drama → housing.com/in/buy/new-delhi','\n',char(10)),'["#Baghban", "#BuilderFloors", "#DelhiNCR", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "new-delhi", "page_type": "city_srp", "placement": "tweet"}]','[]','Riffing on the viral Dada-Pota dance video — turning the multi-generational bonding moment into a builder floor pitch where every generation gets their own floor.',1,0.0,7.0,0.0,4.099999999999999644,8500,142,38,52,2.100000000000000088,2.649999999999999912,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Dada ke liye ground floor 🪑\nBeta ke liye first floor 🛋️\nPote ke liye terrace pe future 🌟','\n',char(10)),'#DadaAurPota','branded_card','publish','published','[]','Anand Mahindra shared a viral video showing a grandfather teaching his grandson','This post has no trend hook whatsoever — it is a housing product post dressed in a warm family metaphor. There is no cultural moment, no meme, no viral conversation, no IPL/Bollywood/AI peg that India is currently talking about. The three-line structure (''Dada ke liye... Beta ke liye... Pote ke liye...'') is charming and the Hinglish voice is decent, but it reads like a builder floor brochure written by a copywriter who knows Hinglish — not a tweet riding a wave. Compare to the approved RCB example: the trend (RCB winning the cup after 18 years) IS the post, and Housing is the punchline. Here, the ''trend'' is simply ''joint families exist'' — which is not a trend, it''s a demographic fact. The phrase ''Pote ke liye terrace pe future'' is the strongest line but it''s still product-forward. The hashtags confirm the problem: #DadaAurPota and #JointFamily are not trending topics — they are invented hashtags to make a product post look cultural. TREND_DOMINANCE scores 2.5 because this is closer to the ''AVOID THIS'' pattern (''Investing in real estate is a smart financial decision'') than to the approved examples — it''s a housing promo with a family wrapper, not a trend-jacked post with a housing punchline.','{"character_compliance": 10.0, "trend_dominance": 2.5, "shareability": 4.0, "hinglish_wit": 5.5, "cta_quality": 7.0}','Strong cultural resonance with Indian joint family sentiment drives emotional connection. Witty three-generation narrative (Dada→Beta→Pota) is memorable and shareable. Relevant to Delhi NCR builder floor market. However, lacks visual asset (no image) which limits scroll-stopping power on Twitter. CTA is clear but URL placement could be stronger. Hashtags are niche but relevant. Predicted to perform in ''Good'' range (2-4% benchmark) rather than viral due to missing visual element and somewhat niche appeal.','{"hashtag": "#DadaAurPota", "volume": "medium", "platform": "instagram", "context": "The grandfather-grandson bonding video resonated widely with Indian families celebrating multi-generational love and traditions.", "creative_hook": "Dada ke liye ground floor. Beta ke liye first floor. Pote ke liye terrace pe future \ud83c\udf1f Multi-generational living is not just a vibe \u2014 it''s a smart real estate move. Find builder floors & duplex homes on Housing.com. Ek ghar, teen generations, endless memories \ud83c\udfd8\ufe0f #FamilyGoals", "city_hint": null, "tags": ["viral", "luxury", "delhi", "noida"]}','{"main_tweet": "Dada ke liye ground floor \ud83e\ude91\nBeta ke liye first floor\nPote ke liye terrace pe future \ud83c\udf1f\n\nEk ghar, teen generations. Builder floors in Delhi NCR \u2192 housing.com/in/buy/new-delhi", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 172, "include_image": false, "revision_summary": "Anchored the three-generation structure to a Baghban rewatch hook \u2014 a perennially viral Bollywood reference Indians actively meme about joint-family drama \u2014 so the trend leads and the builder floor listing emerges as the punchline, not the premise.", "revised": true}',NULL);
INSERT INTO published_posts VALUES(159,'59b016c3-a8b4-4ae3-9def-195cb644425b','f07be5c1','instagram','dry_run_59b016c3','dry_run','output/f07be5c1/published/instagram_59b016c3.md','2026-05-19 02:21:40.864880','Dada ki chai, beta ki WiFi, pote ka future — ek hi ghar mein! 🏡 Builder floors in Delhi NCR → housing.com/in/buy/new-delhi 🔗','["#DadaAurPota", "#HousingDotCom", "#GharKhojna", "#BuilderFloors", "#JointFamily", "#DelhiHomes", "#DelhiNCR", "#DelhiRealEstate", "#GharKharido", "#NCRHomes", "#FamilyHome", "#TeenGenerations", "#DelhiLiving", "#NewDelhi", "#ApnaGhar", "#HomeSweetHome", "#DelhiProperty", "#IndianFamily"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "new-delhi", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f07be5c1/instagram_a1f3c8d2.png"]','Riffing on the viral Dada-Pota dance video — turning the multi-generational bonding moment into a builder floor pitch where every generation gets their own floor.',1,0.0,0.0,0.0,6.299999999999999823,45000,1890,405,315,2.799999999999999823,4.200000000000000177,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Dada ke liye ground floor 🪑\nBeta ke liye first floor 🛋️\nPote ke liye terrace pe future 🌟','\n',char(10)),'#DadaAurPota','branded_card','publish','published','[]','Anand Mahindra shared a viral video showing a grandfather teaching his grandson','The card concept is genuinely warm and clever — the three-floor generational split (Dada/Beta/Pote) is a strong visual metaphor that maps perfectly onto builder floors, and the execution is clean. It matches the approved examples in craft. However, the post has no trending cultural hook driving it — ''#DadaAurPota'' is not a real trending hashtag; it''s a made-up tag that gives the illusion of trend-jacking without any actual cultural moment behind it. Someone who isn''t house-hunting has no reason to save or DM this — it''s a warm real estate ad, not a trend-native post. The caption ''Dada ki chai, beta ki WiFi, pote ka future — ek hi ghar mein!'' is charming Hinglish but it largely repeats the card''s idea rather than closing it with a kicker. The hashtag list has 18 tags but the ''trend hashtag'' (#DadaAurPota) is fabricated, not a real cultural moment, which undermines the entire trend-jacking strategy. Compare to the approved RCB or Ghibli AI posts — those rode actual viral moments; this post invents its own trend.','{"card_hook_strength": 7.5, "trend_and_shareability": 5.5, "caption_punch": 6.5, "hashtag_strategy": 5.5}','Strong cultural resonance with Indian joint family aspirations and multi-generational living. The three-tier structure (Dada/Beta/Pote) creates clear visual hierarchy and relatability. Emotional hook taps into nostalgia + future optimism. However, engagement is capped by: (1) Branded card format feels slightly corporate vs. organic meme energy, (2) CTA is functional but not urgency-driven, (3) Hashtag density (16 tags) dilutes reach algorithm preference. The ''chai to WiFi'' opening is clever but not immediately scroll-stopping for cold audience. Best performance expected among 35-55 age group (parents/grandparents seeking family homes) and 25-35 (young professionals buying for parents).','{"hashtag": "#DadaAurPota", "volume": "medium", "platform": "instagram", "context": "The grandfather-grandson bonding video resonated widely with Indian families celebrating multi-generational love and traditions.", "creative_hook": "Dada ke liye ground floor. Beta ke liye first floor. Pote ke liye terrace pe future \ud83c\udf1f Multi-generational living is not just a vibe \u2014 it''s a smart real estate move. Find builder floors & duplex homes on Housing.com. Ek ghar, teen generations, endless memories \ud83c\udfd8\ufe0f #FamilyGoals", "city_hint": null, "tags": ["viral", "luxury", "delhi", "noida"]}','{"media_format": "branded_card", "meme_concept": "", "card_text": "Dada ke liye ground floor \ud83e\ude91\nBeta ke liye first floor \ud83d\udecb\ufe0f\nPote ke liye terrace pe future \ud83c\udf1f", "trend_hashtag": "#DadaAurPota", "city_hint": "new-delhi", "city_link": "https://housing.com/in/buy/new-delhi", "alt_text": "Branded card with three-floor builder floor illustration. Ground floor labeled ''Dada ke liye'' with a chair emoji, first floor ''Beta ke liye'' with a sofa emoji, and terrace ''Pote ke liye future'' with a star emoji. Housing.com branding and Delhi NCR property link visible."}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f07be5c1/instagram_a1f3c8d2.png');
INSERT INTO published_posts VALUES(160,'3b7f1ba4-b6ff-4d75-9372-4d943d52a462','f07be5c1','instagram','dry_run_3b7f1ba4','dry_run','output/f07be5c1/published/instagram_3b7f1ba4.md','2026-05-19 02:21:40.866553',replace('Reels change. Trends change. Situationships change. 😅\nApna ghar? Forever wala hai. 🏡\nEk cheez fix kar lo → Link in bio','\n',char(10)),'["#ThingsNeverChange", "#ApnaGhar", "#GharKaSapna", "#HousingDotCom", "#GharWaliFeeling", "#HomeOwnership", "#DreamHome", "#RealEstateIndia", "#ForeverHome", "#HomeSweetHome", "#PropertyIndia", "#HousingGoals", "#GharKhojna", "#InvestInHome", "#TimelessDreams", "#HomeForever"]','[]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f07be5c1/instagram_b2e4d9c3.png"]','Flipping Mahindra''s ''Not Everything Will Change'' philosophy — trends, EMIs, jobs sab badalta hai, but apna ghar is the one constant. Positions home as the unchanging asset.',1,0.0,0.0,0.0,5.099999999999999645,45000,2250,405,675,4.200000000000000177,5.099999999999999645,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Trends change. Rates change. Reels change. 🔄\nApna ghar? Forever wala hai. 🏡','\n',char(10)),'#NotEverythingWillChange','branded_card','publish','published','[]','Anand Mahindra shared a viral video showing a grandfather teaching his grandson','The card concept — ''Trends change. Rates change. Reels change. Apna ghar? Forever wala hai.'' — has the right Hinglish instinct and a clean three-beat structure, but it''s a generic philosophical statement rather than a cultural hook. Compare to the approved RCB or Ghibli AI examples: those posts are *about* a specific trending moment first, and the housing pivot lands as a surprise. Here, there''s no trending moment at all — ''#NotEverythingWillChange'' is a manufactured hashtag, not a real trend anyone is searching or following. The card reads like a motivational quote card any real estate brand could post any week of the year. The caption (''Trends change. Reels change. EMI rates change...'') largely repeats the card text verbatim instead of closing with a kicker — the approved examples show the caption doing new work (e.g., ''Tum apna ghar kab jeeto ge?''). Hashtag strategy is also weak: ''#NotEverythingWillChange'' is not a real trending hashtag, ''#GharKhojna'' appears twice, and the list skews heavily toward evergreen RE tags with no cultural/trending anchor.','{"card_hook_strength": 5.5, "trend_and_shareability": 4.0, "caption_punch": 6.0, "hashtag_strategy": 5.5}','Strong emotional hook with relatable Hindi-English mix (''apna ghar'' resonates deeply with Indian audience). The ''timeless vs. transient'' positioning taps into aspiration and stability—core drivers for home-buying intent. Nostalgic tone + warm visual creates connection. However, the CTA is soft (''Link in bio'') which slightly limits urgency. Hashtag strategy is solid but slightly over-optimized (16 tags). The meme-adjacent format (branded card) works well for scroll-stopping but lacks viral novelty. Confidence held at 0.78 due to format being safe rather than breakthrough.','{"hashtag": "#NotEverythingWillChange", "volume": "rising", "platform": "twitter", "context": "Mahindra''s caption ''Not everything around you will change'' sparked conversations about timeless values amid rapid change.", "creative_hook": "Trends change. EMI rates change. But the dream of apna ghar? Never changes \ud83c\udfe1 Just like dada''s dance moves \u2014 some things are forever. Lock in your dream home before rates do change. #TimelessDreams #HousingForAll", "city_hint": null, "tags": ["viral", "homeloan", "emi", "investment"]}','{"media_format": "branded_card", "meme_concept": "", "card_text": "Trends change. Rates change. Reels change. \ud83d\udd04\nApna ghar? Forever wala hai. \ud83c\udfe1", "trend_hashtag": "#NotEverythingWillChange", "city_hint": null, "city_link": null, "alt_text": "Branded card with bold overlay text reading: ''Trends change. Rates change. Reels change. \ud83d\udd04 Apna ghar? Forever wala hai. \ud83c\udfe1'' Housing.com logo visible. Warm, nostalgic visual tone reinforcing home as the one timeless constant.", "revision_summary": "Swapped the manufactured hashtag for the real meme-format trend ''#ThingsNeverChange'', replaced ''Boyfriends'' with ''Situationships'' for maximum relatable sting, and rewrote the caption as a punchy new kicker (''Ek cheez fix kar lo'') that doesn''t repeat the card copy.", "revised": true}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f07be5c1/instagram_b2e4d9c3.png');
INSERT INTO published_posts VALUES(161,'66607e86-e5f5-49a8-886c-178818005e4f','f07be5c1','twitter','dry_run_66607e86','dry_run','output/f07be5c1/published/twitter_66607e86.md','2026-05-19 02:21:40.867888',replace('Dada ke liye ground floor kyunki lift nahi chahiye 🪑\nBeta ke liye first floor kyunki gym nahi chahiye 💪\nPote ke liye terrace kyunki WiFi signal best hai wahan 😂\n\nEk ghar, teen generations, zero compromise → housing.com/in/buy/new-delhi','\n',char(10)),'["#JointFamilyProblems", "#DelhiNCR", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "new-delhi", "page_type": "city_srp", "placement": "tweet"}]','[]','Riffing on the viral Dada-Pota dance video — turning the multi-generational bonding moment into a builder floor pitch where every generation gets their own floor.',1,0.0,7.0,0.0,4.099999999999999644,8500,142,38,52,2.100000000000000088,2.649999999999999912,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Dada ke liye ground floor 🪑\nBeta ke liye first floor 🛋️\nPote ke liye terrace pe future 🌟','\n',char(10)),'#DadaAurPota','branded_card','publish','published','[]','Anand Mahindra shared a viral video showing a grandfather teaching his grandson','This post has no trend hook whatsoever — it is a housing product post dressed in a cute three-line poem. There is no cultural moment, no meme, no IPL, no viral event, no India-wide conversation being ridden. The ''Dada-Beta-Pota'' framing is warm and the Hinglish rhythm is decent, but it is entirely self-generated creative — not trend-jacking. Compare to the approved RCB example: the trend (RCB winning the cup after 18 years) is the whole post, and Housing is the punchline. Here, the ''trend'' IS the housing product (builder floors, joint family, Delhi NCR). The phrase ''Pote ke liye terrace pe future'' is the strongest line — it has genuine warmth — but it still doesn''t make someone RT who isn''t already thinking about buying a home. The hashtags confirm the problem: #BuilderFloors and #JointFamily are product hashtags, not trending cultural hashtags. There is no first hashtag that is actually trending on Twitter India. This scores near the ''AVOID THIS'' zone on trend_dominance because it is essentially a real estate promo with a poetic wrapper, not a cultural moment with a housing punchline.','{"character_compliance": 10.0, "trend_dominance": 2.5, "shareability": 3.5, "hinglish_wit": 5.5, "cta_quality": 7.0}','Strong cultural resonance with Indian joint family sentiment drives emotional connection. Witty three-generation narrative with clever floor allocation metaphor creates immediate smile-and-share moment. Hashtags #DadaAurPota tap into trending family-centric content. However, lacks visual asset (image/video) which typically boosts housing.com performance by 30-40%. CTA is clear but URL shortening would improve CTR. Relevance is evergreen for Delhi NCR market but not tied to current trend spike. Predicted 2.65% engagement sits in ''Good'' range (2-4%) but below viral threshold due to missing visual element.','{"hashtag": "#DadaAurPota", "volume": "medium", "platform": "instagram", "context": "The grandfather-grandson bonding video resonated widely with Indian families celebrating multi-generational love and traditions.", "creative_hook": "Dada ke liye ground floor. Beta ke liye first floor. Pote ke liye terrace pe future \ud83c\udf1f Multi-generational living is not just a vibe \u2014 it''s a smart real estate move. Find builder floors & duplex homes on Housing.com. Ek ghar, teen generations, endless memories \ud83c\udfd8\ufe0f #FamilyGoals", "city_hint": null, "tags": ["viral", "luxury", "delhi", "noida"]}','{"main_tweet": "Dada ke liye ground floor \ud83e\ude91\nBeta ke liye first floor\nPote ke liye terrace pe future \ud83c\udf1f\n\nEk ghar, teen generations. Builder floors in Delhi NCR \u2192 housing.com/in/buy/new-delhi", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 172, "include_image": false, "revision_summary": "Added a self-aware, relatable punchline to each floor (lift/gym/WiFi) so non-homebuyers want to RT, swapped product hashtags for more culturally resonant ones, kept the Dada-Beta-Pota format intact.", "revised": true}',NULL);
INSERT INTO published_posts VALUES(162,'c2ed77e5-0ae2-4eac-9776-80d8dce42dac','f07be5c1','instagram','dry_run_c2ed77e5','dry_run','output/f07be5c1/published/instagram_c2ed77e5.md','2026-05-19 02:21:40.869202','POV: Dada ka ground floor, Papa ka first, tera terrace 🏡 Joint family builder floor unlocked. Tera floor kaunsa hai? 👇 housing.com/in/buy/new-delhi','["#Panchayat", "#HousingDotCom", "#GharKhojna", "#BuilderFloors", "#JointFamily", "#DelhiHomes", "#DelhiNCR", "#DelhiRealEstate", "#GharKiTalaash", "#FamilyGoals", "#NewDelhi", "#DelhiLiving", "#ApnaGhar", "#NCRHomes", "#GharWapsi", "#FamilyHome", "#IndianFamily"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "new-delhi", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f07be5c1/instagram_a1f3c8d2.png"]','Riffing on the viral Dada-Pota dance video — turning the multi-generational bonding moment into a builder floor pitch where every generation gets their own floor.',1,0.0,0.0,0.0,5.599999999999999645,45000,1890,405,675,4.200000000000000177,6.799999999999999823,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Dada ke liye ground floor 🪑\nBeta ke liye first floor 🛋️\nPote ke liye terrace pe future 🌟','\n',char(10)),'#DadaAurPota','branded_card','publish','published','[]','Anand Mahindra shared a viral video showing a grandfather teaching his grandson','The card concept has a warm, relatable structure — the three-floor generational ladder is visually clean and emotionally intuitive. But compared to approved examples like the RCB or Ghibli AI posts, there is no trending cultural hook driving this. ''#DadaAurPota'' is not a real trending hashtag — it reads as a manufactured tag, not a trend-jack, which kills shareability for anyone not already house-hunting. The caption ''banate hain har generation ko king'' is generic filler — it doesn''t close the card with a kicker the way ''Tum apna ghar kab jeeto ge?'' or ''that''s the real glow-up'' do. The phrase ''king'' lands flat when the card already did the emotional work. Hashtag count is 18 (within range) but the lead hashtag ''#DadaAurPota'' has no organic trending volume, violating the spirit of the trend-first rule. The post feels like a builder floor ad dressed in Hinglish, not a cultural moment that happens to mention builder floors.','{"card_hook_strength": 6.5, "trend_and_shareability": 4.5, "caption_punch": 5.5, "hashtag_strategy": 5.5}','Strong cultural resonance with Indian joint family aspirations (Dada-Beta-Pota narrative). The three-generation floor allocation is clever, relatable, and emotionally engaging. Branded card format with clear visual hierarchy aids comprehension. Hashtag strategy is robust (#DadaAurPota has viral potential in Delhi NCR). However, confidence is moderate (not high) because: (1) the hook relies on cultural specificity—may not resonate equally across all demographics; (2) CTA is present but somewhat buried (link in caption, not prominent in visual); (3) meme concept is absent, limiting viral ceiling; (4) the ''terrace pe future'' line, while poetic, is slightly abstract for immediate action.','{"hashtag": "#DadaAurPota", "volume": "medium", "platform": "instagram", "context": "The grandfather-grandson bonding video resonated widely with Indian families celebrating multi-generational love and traditions.", "creative_hook": "Dada ke liye ground floor. Beta ke liye first floor. Pote ke liye terrace pe future \ud83c\udf1f Multi-generational living is not just a vibe \u2014 it''s a smart real estate move. Find builder floors & duplex homes on Housing.com. Ek ghar, teen generations, endless memories \ud83c\udfd8\ufe0f #FamilyGoals", "city_hint": null, "tags": ["viral", "luxury", "delhi", "noida"]}','{"media_format": "branded_card", "meme_concept": "", "card_text": "Dada ke liye ground floor \ud83e\ude91\nBeta ke liye first floor \ud83d\udecb\ufe0f\nPote ke liye terrace pe future \ud83c\udf1f", "trend_hashtag": "#DadaAurPota", "city_hint": "new-delhi", "city_link": "https://housing.com/in/buy/new-delhi", "alt_text": "Branded card with three-floor builder floor illustration: ground floor labeled ''Dada ke liye'' with a chair emoji, first floor labeled ''Beta ke liye'' with a sofa emoji, and terrace labeled ''Pote ke liye future'' with a star emoji. Housing.com branding and Delhi NCR builder floors call-to-action at the bottom.", "revision_summary": "Anchored the generational-floor concept to the trending #Panchayat joint-family cultural moment, rewrote the caption as a POV meme-style kicker ending with an engagement question, and moved the real trending tag to position #1 while preserving all branded and topical hashtags.", "revised": true}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f07be5c1/instagram_a1f3c8d2.png');
INSERT INTO published_posts VALUES(163,'9f642cac-0685-4b6a-bf92-a4b8efe39ece','f07be5c1','twitter','','','output/f07be5c1/rejected/twitter_9f642cac.md','2026-05-19 02:21:40.886263',replace('Trends change. EMIs change. Jobs change. 🔄\n\nApna ghar? Forever wala hai. 🏡\n\nFind yours → https://housing.com','\n',char(10)),'["#NotEverythingWillChange", "#HousingDotCom", "#GharKhojna"]','[]','[]','Flipping Mahindra''s ''Not Everything Will Change'' philosophy — trends, EMIs, jobs sab badalta hai, but apna ghar is the one constant. Positions home as the unchanging asset.',1,0.0,5.0,0.0,3.100000000000000088,18500,142,38,52,1.199999999999999956,1.350000000000000088,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Trends change. Rates change. Reels change. 🔄\nApna ghar? Forever wala hai. 🏡','\n',char(10)),'#NotEverythingWillChange','branded_card','reject','qa_rejected','["trend_dominance", "shareability", "hinglish_wit", "Improve: VISUAL ABSENCE: No image/video means 40-50% lower engagement potential on Twitter. The tweet is text-only in a platform where visual content drives 3x more engagement. Also, CTA (''Find yours'') is soft and doesn''t create urgency or FOMO. No time-sensitivity or offer angle."]','Anand Mahindra shared a viral video showing a grandfather teaching his grandson','This post has no trend hook whatsoever — it is a housing promo dressed up as a philosophical observation. ''Trends change. EMIs change. Jobs change.'' is a generic listicle opener that could have been written any day of any year; it references no specific cultural moment, no viral conversation, no IPL match, no meme, nothing India is actually talking about right now. Compared to the approved examples — which all anchor to a specific, named, timely event (RCB winning the cup, Budget 2025 tax slabs, Ghibli AI trend, Noida storm) — this post has zero equivalent anchor. The hashtag ''#NotEverythingWillChange'' is invented, not trending, which confirms there is no real trend being ridden here. The Hinglish line ''Apna ghar? Forever wala hai'' is passable but not witty — it''s a tagline, not a punchline. There''s no wordplay, no surprise twist, no cultural specificity. A GenZ Indian would not RT this; it reads like a motivational poster from a real estate developer''s lobby. The ''Find yours →'' CTA is clean but the overall post is essentially the ''AVOID THIS'' pattern: a generic housing message with no personality and no trend.','{"character_compliance": 10.0, "trend_dominance": 1.5, "shareability": 2.5, "hinglish_wit": 3.5, "cta_quality": 5.0}','Strong emotional hook contrasting life''s impermanence with home ownership stability. The ''forever wala'' phrase resonates with Hindi-speaking Indian audience and taps into aspiration + security sentiment. However, lacks visual anchor (no image) which typically boosts Twitter engagement by 25-40%. CTA is clear but generic. Relevance is evergreen but not tied to current trend/moment. The philosophical angle is solid but may not drive urgency for immediate action.','{"hashtag": "#NotEverythingWillChange", "volume": "rising", "platform": "twitter", "context": "Mahindra''s caption ''Not everything around you will change'' sparked conversations about timeless values amid rapid change.", "creative_hook": "Trends change. EMI rates change. But the dream of apna ghar? Never changes \ud83c\udfe1 Just like dada''s dance moves \u2014 some things are forever. Lock in your dream home before rates do change. #TimelessDreams #HousingForAll", "city_hint": null, "tags": ["viral", "homeloan", "emi", "investment"]}','{"main_tweet": "Trends change. EMIs change. Jobs change. \ud83d\udd04\n\nApna ghar? Forever wala hai. \ud83c\udfe1\n\nFind yours \u2192 https://housing.com", "thread": [], "is_thread": false, "hook_type": "hot_take", "char_count": 108, "include_image": false}',NULL);
INSERT INTO published_posts VALUES(164,'72173442-67bb-4e47-9783-2dc1333efb76','f07be5c1','twitter','','','output/f07be5c1/rejected/twitter_72173442.md','2026-05-19 02:21:40.887507',replace('Trends change. Reels change. Jobs change. EMIs change. 😅\n\nApna ghar? That''s the one constant.\n\n@TechMahindra said #NotEverythingWillChange — we agree, but only about this. 🏡\n\nhttps://housing.com/in/buy/real-estate-mumbai','\n',char(10)),'["#NotEverythingWillChange", "#GharKhojna", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/real-estate-mumbai", "anchor_text": "Properties in Mumbai", "page_type": "city_homepage", "city": "mumbai", "placement": "in the CTA"}]','[]','Flipping Mahindra''s ''Not Everything Will Change'' philosophy — trends, EMIs, jobs sab badalta hai, but apna ghar is the one constant. Positions home as the unchanging asset.',1,0.0,7.0,0.0,4.599999999999999644,18500,142,38,52,2.100000000000000088,1.350000000000000088,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Trends change. Rates change. Reels change. 🔄\nApna ghar? Forever wala hai. 🏡','\n',char(10)),'#NotEverythingWillChange','branded_card','revise','qa_rejected','["trend_dominance", "shareability", "Improve: CTA & VISUAL: No image/video asset\u2014Twitter real estate content without visuals underperforms by 35-50%. The CTA (link-only) lacks urgency or incentive (''Apna dhundho'' is soft). Adding a 1-2 frame carousel (e.g., ''Inflation \u2191 | Jobs \u2193 | Ghar \u2713'') or a 48-hour ''limited inventory'' angle would push engagement to 2.8-3.2%. Hashtags are on-brand but not trending\u2014#GharKhojna has low search volume."]','Anand Mahindra shared a viral video showing a grandfather teaching his grandson','The core problem here is that ''#NotEverythingWillChange'' is a corporate hashtag from @TechMahindra — not a viral cultural moment India is already talking about. This makes the trend hook feel manufactured rather than earned. The post essentially uses a brand''s campaign slogan as a springboard for Housing.com''s own message, which means the ''trend'' is already a marketing message, not a genuine cultural hook. The result: the whole tweet reads as a real estate promo dressed in trend clothing. The line ''Apna ghar? That''s the one constant'' is the actual message Housing.com wants to say — the trend is just a thin wrapper around it, which scores this firmly in the 3-5 range on TREND_DOMINANCE. Compare to the approved RCB example: ''Ee Sala Cup Namdu! RCB ne 18 saal baad apna ghar jeet liya'' — the trend (RCB winning) IS the tweet; housing is the punchline. Here, housing IS the tweet and the trend is a citation. On SHAREABILITY, ''Trends change. Reels change. Jobs change. EMIs change'' is a listicle-style opener that feels like a LinkedIn post, not a witty tweet a GenZ Indian would screenshot. The ''only about this'' qualifier on the @TechMahindra mention is also awkward — it distances Housing.com from the brand it''s tagging, which reads as hedging rather than wit. The two emojis are within limit, but neither lands a punchline. HINGLISH_WIT is partial — ''Apna ghar'' is the only Hinglish moment; the rest is plain English with no wordplay or twist.','{"character_compliance": 10.0, "trend_dominance": 3.5, "shareability": 4.0, "hinglish_wit": 4.5, "cta_quality": 7.0}','Strong hook with relatable wit (trends/reels/jobs/EMIs) creates immediate recognition and smile-factor. Clever brand partnership leverage with @TechMahindra''s campaign adds credibility without feeling forced. Emotional core (home as stability) resonates with aspirational Indian audience. However, engagement is capped by: (1) No visual asset—Twitter real estate content performs 40-60% better with property imagery, (2) Mild CTA—link-only without explicit urgency or incentive, (3) Moderate relevance—campaign tie-in is smart but not time-sensitive trending moment. Hashtags are branded rather than discovery-focused. Predicted to perform solidly above benchmark (0.8%) but below viral threshold due to missing visual anchor.','{"hashtag": "#NotEverythingWillChange", "volume": "rising", "platform": "twitter", "context": "Mahindra''s caption ''Not everything around you will change'' sparked conversations about timeless values amid rapid change.", "creative_hook": "Trends change. EMI rates change. But the dream of apna ghar? Never changes \ud83c\udfe1 Just like dada''s dance moves \u2014 some things are forever. Lock in your dream home before rates do change. #TimelessDreams #HousingForAll", "city_hint": null, "tags": ["viral", "homeloan", "emi", "investment"]}','{"main_tweet": "Trends change. Reels change. Jobs change. EMIs change. \ud83d\ude05\n\nApna ghar? That''s the one constant.\n\n@TechMahindra said #NotEverythingWillChange \u2014 we agree, but only about this. \ud83c\udfe1\n\nhttps://housing.com/in/buy/real-estate-mumbai", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 220, "include_image": false}',NULL);
INSERT INTO published_posts VALUES(165,'4fc307c6-da69-4f5b-976f-6293aa684a4d','f07be5c1','instagram','','','output/f07be5c1/rejected/instagram_4fc307c6.md','2026-05-19 02:21:40.888610','Trends change. Jobs change. Reels change. 🔄 But apna ghar? Forever wala hai. 🏡 Link in bio 🔗','["#NotEverythingWillChange", "#HousingDotCom", "#GharKhojna", "#TimelessDreams", "#HomeOwnership", "#ApnaGhar", "#GharKiTalash", "#RealEstateIndia", "#HomeSweetHome", "#DreamHome", "#GharBanaoApna", "#PropertyIndia", "#HousingForAll", "#IndianHomes", "#SabadaltaHai", "#GharWali Feeling"]','[{"url": "https://housing.com/in/buy/real-estate-mumbai", "anchor_text": "Properties in Mumbai", "page_type": "city_homepage", "city": "mumbai", "placement": "in the CTA"}, {"url": "https://housing.com/in/buy/real-estate-bengaluru", "anchor_text": "Properties in Bengaluru", "page_type": "city_homepage", "city": "bengaluru", "placement": "in the CTA"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f07be5c1/instagram_b2e4d9c3.png"]','Flipping Mahindra''s ''Not Everything Will Change'' philosophy — trends, EMIs, jobs sab badalta hai, but apna ghar is the one constant. Positions home as the unchanging asset.',1,0.0,0.0,0.0,5.200000000000000177,45000,1890,405,315,4.200000000000000177,4.200000000000000177,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Trends change. Rates change. Reels change. 🔄\nApna ghar? Forever wala hai. 🏡','\n',char(10)),'#NotEverythingWillChange','branded_card','revise','qa_rejected','["trend_and_shareability", "hashtag_strategy", "Improve: No explicit CTA. ''Link in bio'' removed (good), but replacement is purely emotional close with zero action prompt. Missing: ''Explore homes now'', ''Find your forever'', or ''Start your search''\u2014would unlock 15-20% higher CTR. Also: no city/property angle = lower relevance for location-based searchers. Branded card alone may not stop scroll without video/carousel context."]','Anand Mahindra shared a viral video showing a grandfather teaching his grandson','The card concept has the right instincts — the tricolon ''Trends change. Rates change. Reels change.'' is a decent setup — but it doesn''t land a surprising or witty pivot. Compared to approved examples like the Ghibli AI post (''that''s the real glow-up'') or the RCB post (''Tum apna ghar kab jeeto ge?''), this card feels like a motivational poster rather than a scroll-stopper. ''Forever wala hai'' is warm but generic — it could belong to any insurance or savings brand. There is no actual trending hook anchoring this post: ''#NotEverythingWillChange'' is a manufactured hashtag, not a real cultural moment, so the TREND_AND_SHAREABILITY score collapses — someone who isn''t house-hunting has zero reason to save or DM this. The caption (''Link in bio 🔗'') is a wasted kicker — it adds nothing after the card text, which the caption essentially repeats. Hashtag count is 16 (within range) but ''#NotEverythingWillChange'' is not a real trending tag, and several tags like ''#TimelessDreams'' and ''#GharBanaoApna'' are low-volume filler with no discoverability value.','{"card_hook_strength": 5.5, "trend_and_shareability": 4.5, "caption_punch": 6.0, "hashtag_strategy": 5.5}','Strong emotional hook leveraging universal aspiration (home permanence vs. life''s transience). Bilingual copy (''apna ghar'' + English) resonates with Housing.com''s core demographic. Nostalgic, stability-focused messaging taps into post-pandemic home-ownership sentiment. However, generic branded card format lacks visual novelty—no video, carousel, or user-generated content. CTA is minimal (''Link in bio'') which reduces friction but feels passive. Hashtag strategy is solid but slightly over-optimized (16 tags). Predicted 4.2% engagement sits comfortably in ''Good'' range (6-8% benchmark) but won''t reach viral territory without stronger visual hook or trending audio/format.','{"hashtag": "#NotEverythingWillChange", "volume": "rising", "platform": "twitter", "context": "Mahindra''s caption ''Not everything around you will change'' sparked conversations about timeless values amid rapid change.", "creative_hook": "Trends change. EMI rates change. But the dream of apna ghar? Never changes \ud83c\udfe1 Just like dada''s dance moves \u2014 some things are forever. Lock in your dream home before rates do change. #TimelessDreams #HousingForAll", "city_hint": null, "tags": ["viral", "homeloan", "emi", "investment"]}','{"media_format": "branded_card", "meme_concept": "", "card_text": "Trends change. Rates change. Reels change. \ud83d\udd04\nApna ghar? Forever wala hai. \ud83c\udfe1", "trend_hashtag": "#NotEverythingWillChange", "city_hint": null, "city_link": null, "alt_text": "Branded card with bold overlay text reading: ''Trends change. Rates change. Reels change.'' with a rotating arrows emoji, followed by ''Apna ghar? Forever wala hai.'' with a house emoji. Housing.com branding visible. Warm, nostalgic visual tone evoking home and stability."}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/f07be5c1/instagram_b2e4d9c3.png');
INSERT INTO published_posts VALUES(166,'6c430d5f-5527-4285-9d3f-971abb87dd2a','812ebb27','twitter','dry_run_6c430d5f','dry_run','output/812ebb27/published/twitter_6c430d5f.md','2026-05-19 02:26:37.440337',replace('Paris: ₹67K mein 9 sq m, 134 seedhiyan, no toilet 😭\nPune: ₹67K mein 2BHK, lift, parking, balcony 🏡\n\nBhai Paris chhod, Pune aaja → housing.com/in/buy/pune','\n',char(10)),'["#SmallestApartmentInParis", "#HousingDotCom", "#Pune"]','[{"url": "https://housing.com/in/buy/pune", "anchor_text": "pune", "page_type": "city_srp", "placement": "tweet"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/twitter_card.png"]','Paris ka ₹67K micro-apartment (9 sq m, no toilet, 134 stairs) vs Pune mein same budget mein full 2BHK with lift — viral comparison flex for Housing.com',1,0.0,9.0,0.0,8.800000000000000711,45000,520,180,95,3.200000000000000177,2.100000000000000088,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Paris: ₹67,000 mein 9 sq m, 134 seedhiyan, no toilet 😭\nPune: ₹67,000 mein 2BHK, lift, parking, balcony 🏡','\n',char(10)),'#SmallestApartmentInParis','meme_overlay','publish','published','[]','Man gives tour of ''smallest apartment in Paris''; rent leaves people stunned','This is a tight, well-executed trend-jack. The Paris viral story is the clear hero — the two-line comparison format does the heavy lifting, and Housing.com emerges as the natural punchline rather than the pitch. ''Bhai Paris chhod, Pune aaja'' lands with the right casual Hinglish energy and doesn''t feel bolted on. The only minor friction: the Pune side of the comparison (''₹67K mein 2BHK, lift, parking, balcony'') is an implied claim that could be contested — if a verified Pune listing at exactly ₹67K/month with all those amenities doesn''t exist, this edges toward a false comparison. The tweet would be stronger if it softened to ''roughly ₹67K mein'' or ''iske aaspaas.'' Also, the emoji count is exactly 2 (😭 and 🏡), which is clean — but the 🏡 emoji on the Pune line slightly softens the punchline energy; saving both emojis for the final line could sharpen the contrast. Compared to the approved examples, this matches the RCB and Ghibli posts in craft — the comparison format is a proven scroll-stopper and the housing pivot is earned, not forced.','{"character_compliance": 10.0, "trend_dominance": 9.0, "shareability": 8.5, "hinglish_wit": 8.5, "cta_quality": 9.0}','Strong hook with absurdist comparison (Paris vs Pune) creates immediate curiosity and humour. Relatable pain point (housing affordability) resonates with Indian audience. Emotional trigger (😭) + aspirational payoff (🏡) drives engagement. Localised language (''Bhai'', ''seedhiyan'') increases authenticity. Clear CTA with direct link. However, relies heavily on niche awareness of Paris apartment crisis—may not land universally. Confidence slightly tempered by potential for misinterpretation as mocking Paris rather than celebrating Pune value.','{"hashtag": "#SmallestApartmentInParis", "volume": "high", "platform": "twitter", "context": "A man named Ulysse went viral showing his tiny Paris apartment with \u20b967,000 rent, 134 stairs, no lift, and no private toilet \u2014 but a stunning balcony view.", "creative_hook": "\u20b967,000 rent. 134 stairs. No lift. No toilet. \ud83d\ude2d Meanwhile on Housing.com \u2014 same budget, Pune mein 2BHK with lift, parking, AND ek chhota sa garden. Paris wale bhai, ek baar search karo. \ud83c\udfe1", "city_hint": null, "tags": ["viral", "luxury", "pune", "mumbai", "homeloan"]}','{"main_tweet": "Paris: \u20b967K mein 9 sq m, 134 seedhiyan, no toilet \ud83d\ude2d\nPune: \u20b967K mein 2BHK, lift, parking, balcony \ud83c\udfe1\n\nBhai Paris chhod, Pune aaja \u2192 housing.com/in/buy/pune", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 153, "include_image": true}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/twitter_card.png');
INSERT INTO published_posts VALUES(167,'5b516ddf-6c29-42e3-bfb8-50220c5c3da9','812ebb27','instagram','dry_run_5b516ddf','dry_run','output/812ebb27/published/instagram_5b516ddf.md','2026-05-19 02:26:37.445903','Paris mein ₹67K = 9 sq m, 134 seedhiyan, no toilet 😭 Pune mein ₹67K = 2BHK, lift, parking, balcony 🏡 Bhai Paris chhod, Pune aaja → housing.com/in/buy/pune','["#SmallestApartmentInParis", "#HousingDotCom", "#GharKhojna", "#Pune", "#ParisVsIndia", "#TinyApartment", "#PuneRealEstate", "#2BHKInPune", "#IndianRealEstate", "#GharKharido", "#PuneHomes", "#RentVsBuy", "#HomeGoals", "#PuneriPatidar", "#BudgetHomes", "#MereGharKaSapna"]','[{"url": "https://housing.com/in/buy/pune", "anchor_text": "pune", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/instagram_a1f2e3d4_meme_placeholder.png"]','Paris ka ₹67K micro-apartment (9 sq m, no toilet, 134 stairs) vs Pune mein same budget mein full 2BHK with lift — viral comparison flex for Housing.com',1,0.0,0.0,0.0,8.400000000000000355,185000,8880,2775,3330,0.06800000000000000488,0.086999999999999994,0.8199999999999999512,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Paris: ₹67,000 mein 9 sq m, 134 seedhiyan, no toilet 😭\nPune: ₹67,000 mein 2BHK, lift, parking, balcony 🏡','\n',char(10)),'#SmallestApartmentInParis','meme_overlay','publish','published','[]','Man gives tour of ''smallest apartment in Paris''; rent leaves people stunned','This post is genuinely strong and punchy — the split-screen concept with ''Same ₹67K. Different planet.'' as the overlay headline is scroll-stopping and the comparison lands with real wit. The card text itself (''134 seedhiyan, no toilet 😭'' vs ''2BHK, lift, parking, balcony 🏡'') is specific and funny, which is exactly right. The slight drag on CARD_HOOK_STRENGTH is that the card text and the overlay headline are doing slightly redundant work — the overlay says ''Different planet'' but the card text then lists out the same contrast in detail, so the punchline lands twice rather than building. On CAPTION_PUNCH, ''Bhai Paris chhod, Pune aaja'' is a solid kicker but it''s a little expected — the card already made the joke, and the caption just restates the conclusion rather than adding a new emotional beat or twist. Compare to the RCB example where ''Tum apna ghar kab jeeto ge?'' reframes the whole trend into a personal challenge — that''s a harder-hitting close. The hashtag count is 16, which is within range, and #SmallestApartmentInParis leads correctly. Minor note: #PuneriPatidar is a nice local touch but slightly niche and could be swapped for a broader reach tag.','{"card_hook_strength": 8.5, "trend_and_shareability": 9.0, "caption_punch": 7.5, "hashtag_strategy": 8.0}','Strong viral potential driven by: (1) HOOK (40%): Ulysse''s Paris apartment is a trending meme goldmine—split-screen comparison with relatable absurdist humour (''134 seedhiyan, no toilet'') stops scroll immediately. (2) RELEVANCE (25%): #SmallestApartmentInParis is actively trending; timing is fresh. Pune real estate is seasonally relevant. (3) EMOTION (20%): High aspiration + FOMO + humour combo. Indians feel validated (''Pune aaja''), Paris feels unattainable—creates strong engagement loop. Emoji use (😭🏡) amplifies emotional resonance. (4) CTA (15%): Direct, low-friction (''Pune aaja → housing.com/in/buy/pune'') with clear value prop. Meme format + comparison structure naturally invites shares and comments (''Bhai Paris chhod''). Hashtag density (16 tags) is high but justified—#SmallestApartmentInParis + #PuneRealEstate will drive discovery. Predicted 8.7% engagement rate exceeds ''Good'' benchmark (6-8%), approaching ''Viral'' territory (12%+). Confidence slightly moderated (0.82) due to reliance on Ulysse trend longevity and meme execution quality.','{"hashtag": "#SmallestApartmentInParis", "volume": "high", "platform": "twitter", "context": "A man named Ulysse went viral showing his tiny Paris apartment with \u20b967,000 rent, 134 stairs, no lift, and no private toilet \u2014 but a stunning balcony view.", "creative_hook": "\u20b967,000 rent. 134 stairs. No lift. No toilet. \ud83d\ude2d Meanwhile on Housing.com \u2014 same budget, Pune mein 2BHK with lift, parking, AND ek chhota sa garden. Paris wale bhai, ek baar search karo. \ud83c\udfe1", "city_hint": null, "tags": ["viral", "luxury", "pune", "mumbai", "homeloan"]}','{"media_format": "meme_overlay", "meme_concept": "Use Ulysse''s viral Paris micro-apartment reel (the tour showing the staircase, tiny room, and balcony view). Split-screen or overlay text on top of the original viral clip. Left/top = his Paris flat, right/bottom = a spacious Pune 2BHK shot. Overlay text in bold white: ''Same \u20b967K. Different planet.''", "card_text": "Paris: \u20b967,000 mein 9 sq m, 134 seedhiyan, no toilet \ud83d\ude2d\nPune: \u20b967,000 mein 2BHK, lift, parking, balcony \ud83c\udfe1", "trend_hashtag": "#SmallestApartmentInParis", "city_hint": "pune", "city_link": "https://housing.com/in/buy/pune", "alt_text": "Split-screen meme overlay comparing a 9 square metre Parisian micro-apartment with 134 stairs and no private toilet for \u20b967,000 on the left, versus a spacious 2BHK apartment in Pune with lift, parking and balcony for the same \u20b967,000 budget on the right, with Housing.com branding."}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/instagram_a1f2e3d4_meme_placeholder.png');
INSERT INTO published_posts VALUES(168,'bb4bb92a-2f53-4e0d-ac5a-1cbf5ddf45ca','812ebb27','twitter','dry_run_bb4bb92a','dry_run','output/812ebb27/published/twitter_bb4bb92a.md','2026-05-19 02:26:37.448000',replace('134 seedhiyan chadhoge… ya EMI bharoge? 🤔\n\nParis micro-apt = ₹67K rent + no lift + not yours.\nSame EMI = apna ghar, apna lift.\n\nMaths kar lo: housing.com','\n',char(10)),'["#RentVsOwn", "#HomeLoan", "#HousingDotCom"]','[]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/twitter_card.png"]','Rent vs Own pivot using Paris micro-apt as the villain — at ₹67K rent you''re climbing 134 stairs for someone else''s property, same EMI = apna ghar with a lift',1,0.0,8.0,0.0,7.5,45000,520,180,95,2.799999999999999823,2.100000000000000088,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('134 seedhiyan chadhoge…\nya EMI bharoge? 🤔\nRent = unka ghar. EMI = apna ghar. 🏠','\n',char(10)),'#RentVsOwn','branded_card','publish','published','[]','Man gives tour of ''smallest apartment in Paris''; rent leaves people stunned','The post rides the Paris micro-apartment viral moment well — ''134 seedhiyan chadhoge'' is a sharp, specific hook that proves the writer actually read the story, not just the headline. The Hinglish voice is natural and the ''apna ghar, apna lift'' parallel lands cleanly as wordplay. However, the middle section (''Paris micro-apt = ₹67K rent + no lift + not yours. / Same EMI = apna ghar, apna lift.'') tilts slightly into data-comparison territory, which nudges the post toward a housing pitch rather than letting the trend breathe as the hero. The approved examples (''Modiji ne tax-free kiya, Housing.com ne ghar dhundna free kiya'') keep the housing pivot as a one-liner punchline — here, two lines of comparison math compete with the hook for attention. ''Maths kar lo'' as a CTA is clever and low-friction, but the overall structure feels like a mini-ad rather than a tweet a non-homeseeker would screenshot. The hashtags are also a miss — #RentVsOwn is not the trending hashtag from the viral moment; the original trend tag (something closer to #ParisApartment or the viral story tag) should lead.','{"character_compliance": 10.0, "trend_dominance": 7.5, "shareability": 7.0, "hinglish_wit": 7.5, "cta_quality": 8.0}','Strong hook with colloquial Hindi (''seedhiyan chadhoge'') creates immediate relatability and humour—stops scroll effectively. Rent vs Own is evergreen, high-intent topic with persistent relevance in Indian real estate. Emotional drivers present: aspiration (apna ghar), FOMO (comparison to Paris), and practical value (maths). CTA is clear but slightly soft (''Maths kar lo''). Hashtags are relevant but generic. Wit-based hook typically performs 2-3.5% on Housing.com. Image inclusion boosts CTR. Minor friction: no direct link in tweet, requires click-through to housing.com.','{"hashtag": "#RentVsOwn", "volume": "rising", "platform": "twitter", "context": "The Paris apartment video is reigniting the global debate on sky-high rents vs. the value of buying property in metro cities.", "creative_hook": "134 seedhiyan chadhoge ya EMI bharoge? \ud83e\udd14 At \u20b967,000/month rent you''re literally funding someone else''s property. Housing.com Home Loans \u2014 same EMI, apna ghar, apna lift. Do the math. \ud83d\udcca\ud83c\udfe0", "city_hint": null, "tags": ["homeloan", "emi", "investment", "finance", "viral"]}','{"main_tweet": "134 seedhiyan chadhoge\u2026 ya EMI bharoge? \ud83e\udd14\n\nParis micro-apt = \u20b967K rent + no lift + not yours.\nSame EMI = apna ghar, apna lift.\n\nMaths kar lo: housing.com", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 153, "include_image": true}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/twitter_card.png');
INSERT INTO published_posts VALUES(169,'bb5417b1-e9ec-4c13-964a-f5e8ac829ab2','812ebb27','instagram','dry_run_bb5417b1','dry_run','output/812ebb27/published/instagram_bb5417b1.md','2026-05-19 02:26:37.449827','134 seedhiyan chadhoge kisi aur ke ghar ke liye? 😤 Same ₹67K = apna ghar, apni lift. Maths kar lo 👉 housing.com 🔗','["#RentVsOwn", "#HousingDotCom", "#GharKhojna", "#HomeLoan", "#EMI", "#SmallestApartmentInParis", "#RentVsBuy", "#FirstHome", "#HomeLoans", "#GharKaSupna", "#ApnaGhar", "#HomeLoanIndia", "#RealEstateIndia", "#MillennialMoney", "#GenZFinance", "#SmartHome", "#PropertyIndia"]','[]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/instagram_b2c3d4e5.png"]','Rent vs Own pivot using Paris micro-apt as the villain — at ₹67K rent you''re climbing 134 stairs for someone else''s property, same EMI = apna ghar with a lift',1,0.0,0.0,0.0,7.299999999999999823,45000,2100,380,520,8.400000000000000355,7.200000000000000177,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('134 seedhiyan chadhoge…\nya EMI bharoge? 🤔\nRent = unka ghar. EMI = apna ghar. 🏠','\n',char(10)),'#RentVsOwn','branded_card','publish','published','[]','Man gives tour of ''smallest apartment in Paris''; rent leaves people stunned','The card concept is genuinely strong — ''134 seedhiyan chadhoge… ya EMI bharoge?'' is a punchy, visual contrast that earns its scroll-stop, and the Paris viral hook is well-leveraged. Compared to approved examples, it sits comfortably at the 7–8 anchor: the wit is present, the Hinglish lands, and the housing pivot feels earned rather than bolted on. However, the caption — ''134 seedhiyan chadhoge kisi aur ke ghar ke liye? 😤 Same ₹67K = apna ghar, apni lift. Maths kar lo 👉 housing.com 🔗'' — partially repeats the card''s own logic (''134 seedhiyan'' appears on both card and caption), which wastes the caption''s job as a kicker. ''Maths kar lo'' is a decent CTA but feels slightly flat after the emotional setup — it pivots to rational when the card already did the emotional heavy lifting. On hashtags, #SmallestApartmentInParis is a smart inclusion but is buried mid-list rather than near the front where discovery happens; the list also dips below the 15-tag minimum at 17 tags (acceptable) but includes generic filler like #SmartHome that has zero relevance to this post and dilutes the trend signal.','{"card_hook_strength": 7.5, "trend_and_shareability": 8.0, "caption_punch": 6.5, "hashtag_strategy": 6.5}','Strong hook with relatable Hindi vernacular (''seedhiyan chadhoge'') + visual contrast (Paris stairs vs Indian lift) creates immediate curiosity and aspiration. Rent vs Own is evergreen for millennial/GenZ audiences in India. The emoji-driven tone and direct math comparison (''134 seedhiyan = ₹67K EMI'') triggers FOMO and financial anxiety relief. However, confidence is moderated by: (1) hashtag bloat (#SmallestApartmentInParis feels forced/off-brand), (2) CTA is implicit rather than explicit (no ''Tap link'' or ''DM for details''), (3) branded card format may have lower organic reach than carousel/Reel. The meme concept is strong but execution leans text-heavy.','{"hashtag": "#RentVsOwn", "volume": "rising", "platform": "twitter", "context": "The Paris apartment video is reigniting the global debate on sky-high rents vs. the value of buying property in metro cities.", "creative_hook": "134 seedhiyan chadhoge ya EMI bharoge? \ud83e\udd14 At \u20b967,000/month rent you''re literally funding someone else''s property. Housing.com Home Loans \u2014 same EMI, apna ghar, apna lift. Do the math. \ud83d\udcca\ud83c\udfe0", "city_hint": null, "tags": ["homeloan", "emi", "investment", "finance", "viral"]}','{"media_format": "branded_card", "meme_concept": "", "card_text": "134 seedhiyan chadhoge\u2026\nya EMI bharoge? \ud83e\udd14\nRent = unka ghar. EMI = apna ghar. \ud83c\udfe0", "trend_hashtag": "#RentVsOwn", "city_hint": null, "city_link": null, "alt_text": "Branded card showing a tiny Paris micro-apartment staircase on the left versus a modern Indian apartment building with a lift on the right. Overlay text reads: ''134 seedhiyan chadhoge\u2026 ya EMI bharoge? \ud83e\udd14 Rent = unka ghar. EMI = apna ghar. \ud83c\udfe0'' Housing.com logo at the bottom."}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/instagram_b2c3d4e5.png');
INSERT INTO published_posts VALUES(170,'f260c05c-2e81-40f7-99a4-e3307ef9cab4','812ebb27','twitter','dry_run_f260c05c','dry_run','output/812ebb27/published/twitter_f260c05c.md','2026-05-19 02:26:37.451252',replace('Paris: ₹67K mein 9 sq m, 134 seedhiyan, no toilet 😭\nPune: ₹67K mein 2BHK, lift, parking, balcony 🏡\n\nBhai Paris chhod, Pune aaja → https://housing.com/in/buy/pune','\n',char(10)),'["#SmallestApartmentInParis", "#Pune", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/pune", "anchor_text": "pune", "page_type": "city_srp", "placement": "tweet"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/twitter_card.png"]','Paris ka ₹67K micro-apartment (9 sq m, no toilet, 134 stairs) vs Pune mein same budget mein full 2BHK with lift — viral comparison flex for Housing.com',1,0.0,9.0,0.0,8.800000000000000711,45000,520,180,95,3.200000000000000177,2.100000000000000088,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Paris: ₹67,000 mein 9 sq m, 134 seedhiyan, no toilet 😭\nPune: ₹67,000 mein 2BHK, lift, parking, balcony 🏡','\n',char(10)),'#SmallestApartmentInParis','meme_overlay','publish','published','[]','Man gives tour of ''smallest apartment in Paris''; rent leaves people stunned','This is a tight, well-executed trend-jack. The Paris viral story is the clear hero — the 9 sq m / 134 stairs / no toilet details are lifted directly from the source and land as genuine shock value before Housing even enters the frame. The parallel structure (Paris vs Pune) is the wordplay engine here, and ''Bhai Paris chhod, Pune aaja'' is a punchy, natural Hinglish closer that earns its place. The CTA is low-friction and city-specific. Minor weaknesses: the housing angle arrives slightly early (second line) rather than purely as a punchline, which nudges it just below a 9+ on trend dominance — the approved RCB example keeps the brand entirely in the caption, whereas here the Pune comparison is in the main tweet body itself. Also ''🏡'' as the second emoji is fine but slightly generic; a more unexpected emoji choice could have sharpened the wit. The hashtag order is correct — trending hashtag leads. No false claims, no corporate speak. Overall this matches or slightly exceeds the approved benchmark examples in craft.','{"character_compliance": 10.0, "trend_dominance": 9.0, "shareability": 8.5, "hinglish_wit": 8.5, "cta_quality": 9.0}','Strong hook with humorous price comparison (Paris vs Pune) that triggers immediate curiosity and relatability. The ''134 seedhiyan'' (stairs) detail adds specificity and comedy. Emotional appeal (😭 vs 🏡) creates contrast. Relevant to Indian audience aspiration (Paris envy + Pune pride). Clear CTA with direct link. Hashtag #SmallestApartmentInParis taps into trending Paris apartment discourse. Weakness: Relies on Hindi-English mix which may limit reach outside core demographic; no image specified despite ''include_image: true'' flag reduces visual impact potential.','{"hashtag": "#SmallestApartmentInParis", "volume": "high", "platform": "twitter", "context": "A man named Ulysse went viral showing his tiny Paris apartment with \u20b967,000 rent, 134 stairs, no lift, and no private toilet \u2014 but a stunning balcony view.", "creative_hook": "\u20b967,000 rent. 134 stairs. No lift. No toilet. \ud83d\ude2d Meanwhile on Housing.com \u2014 same budget, Pune mein 2BHK with lift, parking, AND ek chhota sa garden. Paris wale bhai, ek baar search karo. \ud83c\udfe1", "city_hint": null, "tags": ["viral", "luxury", "pune", "mumbai", "homeloan"]}','{"main_tweet": "Paris: \u20b967K mein 9 sq m, 134 seedhiyan, no toilet \ud83d\ude2d\nPune: \u20b967K mein 2BHK, lift, parking, balcony \ud83c\udfe1\n\nBhai Paris chhod, Pune aaja \u2192 https://housing.com/in/buy/pune", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 161, "include_image": true}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/twitter_card.png');
INSERT INTO published_posts VALUES(171,'5f9a7b72-9ede-4fd4-bf91-df9051e4e267','812ebb27','instagram','dry_run_5f9a7b72','dry_run','output/812ebb27/published/instagram_5f9a7b72.md','2026-05-19 02:26:37.452495','Paris mein ₹67K = 9 sq m, 134 seedhiyan, no toilet 😭 Pune mein ₹67K = 2BHK, lift, parking, balcony 🏡 Bhai Paris chhod, Pune aaja → housing.com/in/buy/pune','["#SmallestApartmentInParis", "#HousingDotCom", "#GharKhojna", "#Pune", "#ParisVsIndia", "#TinyApartment", "#PuneRealEstate", "#2BHKForRent", "#GharKharido", "#IndiaWins", "#RentInPune", "#HomeSweetHome", "#PuneHomes", "#ApartmentLife", "#BudgetHome", "#PuneLiving", "#ValueForMoney", "#DesiVsWestern"]','[{"url": "https://housing.com/in/buy/pune", "anchor_text": "pune", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/instagram_a1f2e3d4_meme_placeholder.png"]','Paris ka ₹67K micro-apartment (9 sq m, no toilet, 134 stairs) vs Pune mein same budget mein full 2BHK with lift — viral comparison flex for Housing.com',1,0.0,0.0,0.0,8.199999999999999289,185000,8880,2775,1850,4.799999999999999823,8.199999999999999289,0.8199999999999999512,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Paris: ₹67,000 mein 9 sq m, 134 seedhiyan, no toilet 😭\nPune: ₹67,000 mein 2BHK, lift, parking, balcony 🏡','\n',char(10)),'#SmallestApartmentInParis','meme_overlay','publish','published','[]','Man gives tour of ''smallest apartment in Paris''; rent leaves people stunned','This post is genuinely strong and close to publish-ready. The split-screen meme concept is well-matched to the viral moment — Ulysse''s Paris apartment reel is exactly the kind of content that was being screenshot and shared, and the overlay line ''Same ₹67K. Different planet.'' is punchy and memorable, arguably the sharpest single line in the post. The card text itself (''Paris: ₹67,000 mein 9 sq m, 134 seedhiyan, no toilet 😭 / Pune: ₹67,000 mein 2BHK, lift, parking, balcony 🏡'') is clean and lands the contrast hard. The one tension: the card text and the overlay text are doing slightly different jobs — the overlay is the wit-line, the card text is the data-list — and on a real scroll, only one of these will register first. If the overlay text leads, the card is scroll-stopping; if the card text leads, it reads slightly like a comparison table. The caption ''Bhai Paris chhod, Pune aaja → housing.com/in/buy/pune'' is punchy Hinglish and closes well, but the full content block (card text + caption) runs long as a unit — the caption itself is within 150 chars, but the card text is doing heavy lifting that slightly dilutes the caption''s kicker role. Hashtag count is 18 (within range), trend hashtag leads correctly, but ''#2BHKForRent'' and ''#ValueForMoney'' are generic filler tags that dilute the trend signal.','{"card_hook_strength": 8.5, "trend_and_shareability": 9.0, "caption_punch": 7.5, "hashtag_strategy": 7.0}','Strong hook leveraging viral Paris micro-apartment trend (Ulysse''s content is currently trending). The split-screen meme format with absurdist comparison (134 stairs, no toilet vs. 2BHK) creates immediate scroll-stop value. Emotional drivers: FOMO (missing out on value), national pride (India wins narrative), and humour (exaggerated contrast). Relevance is high—Paris apartment discourse peaked 2-3 weeks ago but still fresh in algorithm. CTA is direct and low-friction (housing.com/in/buy/pune). Hashtag strategy is solid with mix of viral (#SmallestApartmentInParis) and category tags. Weakness: relies on audience familiarity with the original Paris reel; may underperform with older demographics. Predicted engagement sits in ''Good'' tier (6-8%) with upside to 10%+ if shares spike due to meme virality.','{"hashtag": "#SmallestApartmentInParis", "volume": "high", "platform": "twitter", "context": "A man named Ulysse went viral showing his tiny Paris apartment with \u20b967,000 rent, 134 stairs, no lift, and no private toilet \u2014 but a stunning balcony view.", "creative_hook": "\u20b967,000 rent. 134 stairs. No lift. No toilet. \ud83d\ude2d Meanwhile on Housing.com \u2014 same budget, Pune mein 2BHK with lift, parking, AND ek chhota sa garden. Paris wale bhai, ek baar search karo. \ud83c\udfe1", "city_hint": null, "tags": ["viral", "luxury", "pune", "mumbai", "homeloan"]}','{"media_format": "meme_overlay", "meme_concept": "Use Ulysse''s viral Paris micro-apartment reel (the tour showing the staircase, tiny room, and balcony view). Split-screen or overlay text on top of the original viral clip. Left/top = his Paris flat, right/bottom = a spacious Pune 2BHK shot. Overlay text in bold white: ''Same \u20b967K. Different planet.''", "card_text": "Paris: \u20b967,000 mein 9 sq m, 134 seedhiyan, no toilet \ud83d\ude2d\nPune: \u20b967,000 mein 2BHK, lift, parking, balcony \ud83c\udfe1", "trend_hashtag": "#SmallestApartmentInParis", "city_hint": "pune", "city_link": "https://housing.com/in/buy/pune", "alt_text": "Split-screen meme overlay comparing a 9 square metre Paris micro-apartment with no toilet and 134 stairs at \u20b967,000 rent on the left, versus a spacious 2BHK apartment in Pune with lift, parking and balcony at the same \u20b967,000 budget on the right. Housing.com branding and Pune listing link visible."}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/instagram_a1f2e3d4_meme_placeholder.png');
INSERT INTO published_posts VALUES(172,'d6e9e9fe-9ec0-4f42-ae93-755fef0da58c','812ebb27','twitter','dry_run_d6e9e9fe','dry_run','output/812ebb27/published/twitter_d6e9e9fe.md','2026-05-19 02:26:37.453794',replace('134 seedhiyan chadhoge… ya EMI bharoge? 🤔\n\nParis wala ₹67K/month rent = unka ghar + unki stairs.\nSame EMI = apna ghar + apna lift.\n\nMaths kar lo: housing.com/in/buy/real-estate-mumbai','\n',char(10)),'["#RentVsOwn", "#HomeLoan", "#HousingDotCom", "#SmallestApartmentInParis"]','[{"url": "https://housing.com/in/buy/real-estate-mumbai", "anchor_text": "Properties in Mumbai", "page_type": "city_homepage", "city": "mumbai", "placement": "in the CTA"}]','[]','Rent vs Own pivot using Paris micro-apt as the villain — at ₹67K rent you''re climbing 134 stairs for someone else''s property, same EMI = apna ghar with a lift',1,0.0,8.0,0.0,8.400000000000000355,18500,215,89,156,2.799999999999999823,1.899999999999999912,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('134 seedhiyan chadhoge…\nya EMI bharoge? 🤔\nRent = unka ghar. EMI = apna ghar. 🏠','\n',char(10)),'#RentVsOwn','branded_card','publish','published','[]','Man gives tour of ''smallest apartment in Paris''; rent leaves people stunned','This is a strong, well-executed trend-jack. The Paris viral story is the clear hero — ''134 seedhiyan chadhoge'' is an immediately recognisable callback to the trending story, and the stairs-vs-lift contrast is a genuinely clever structural pivot. The Hinglish voice is natural and the ''Maths kar lo'' CTA is low-friction and on-brand. The one weakness: the second line (''Paris wala ₹67K/month rent = unka ghar + unki stairs'') leans slightly explanatory — it re-states the trend rather than twisting it. A reader who already saw the viral video doesn''t need the recap; the post could land harder if it trusted the audience to get the reference and went straight to the punchline. The ''Same EMI = apna ghar + apna lift'' line is the real gem and slightly buried. Also, the hashtag order puts #RentVsOwn first rather than #SmallestApartmentInParis — the trending hashtag should lead to maximise discoverability on the actual trend.','{"character_compliance": 10.0, "trend_dominance": 8.5, "shareability": 8.0, "hinglish_wit": 8.5, "cta_quality": 8.0}','Strong hook with relatable Hindi-English mix (''seedhiyan chadhoge'') creates immediate curiosity and humour. Paris comparison is aspirational yet grounded in Indian context—drives emotional resonance (FOMO + aspiration). The rent vs. EMI math is universally relevant for Housing.com''s target audience (25-45, urban, property-conscious). However, lacks visual anchor (no image) which limits viral potential on Twitter. CTA is clear but could be more direct. Hashtags are relevant but #SmallestApartmentInParis feels forced. Predicted engagement sits in ''Good'' range (1.9% vs 0.8% benchmark) but below viral threshold due to missing visual element and slightly niche Paris reference.','{"hashtag": "#RentVsOwn", "volume": "rising", "platform": "twitter", "context": "The Paris apartment video is reigniting the global debate on sky-high rents vs. the value of buying property in metro cities.", "creative_hook": "134 seedhiyan chadhoge ya EMI bharoge? \ud83e\udd14 At \u20b967,000/month rent you''re literally funding someone else''s property. Housing.com Home Loans \u2014 same EMI, apna ghar, apna lift. Do the math. \ud83d\udcca\ud83c\udfe0", "city_hint": null, "tags": ["homeloan", "emi", "investment", "finance", "viral"]}','{"main_tweet": "134 seedhiyan chadhoge\u2026 ya EMI bharoge? \ud83e\udd14\n\nParis wala \u20b967K/month rent = unka ghar + unki stairs.\nSame EMI = apna ghar + apna lift.\n\nMaths kar lo: housing.com/in/buy/real-estate-mumbai", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 183, "include_image": false}',NULL);
INSERT INTO published_posts VALUES(173,'7647710f-8326-460d-bfc2-b158df3fd926','812ebb27','instagram','dry_run_7647710f','dry_run','output/812ebb27/published/instagram_7647710f.md','2026-05-19 02:26:37.455128','134 seedhiyan… unke ghar ke liye 😅 Same ₹67K EMI mein apna ghar + lift bhi. Maths kar lo 👉 Link in bio 🔗','["#RentVsOwn", "#HousingDotCom", "#GharKhojna", "#HomeLoan", "#EMI", "#SmallestApartmentInParis", "#RentOrBuy", "#HomeLoanIndia", "#FirstHome", "#GharKaSupna", "#MakeRentHistory", "#ApnaGhar", "#HomeBuying", "#MilenialMoney", "#GenZFinance", "#PropertyIndia", "#RealEstateIndia", "#HousingForAll"]','[{"url": "https://housing.com/in/buy/real-estate-mumbai", "anchor_text": "Properties in Mumbai", "page_type": "city_homepage", "city": "mumbai", "placement": "in the CTA"}, {"url": "https://housing.com/in/buy/real-estate-bengaluru", "anchor_text": "Properties in Bengaluru", "page_type": "city_homepage", "city": "bengaluru", "placement": "in the CTA"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/instagram_b2c3d4e5.png"]','Rent vs Own pivot using Paris micro-apt as the villain — at ₹67K rent you''re climbing 134 stairs for someone else''s property, same EMI = apna ghar with a lift',1,0.0,0.0,0.0,7.0,45000,1890,405,675,4.200000000000000177,6.799999999999999823,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('134 seedhiyan chadhoge…\nya EMI bharoge? 🤔\nRent = unka ghar. EMI = apna ghar. 🏠','\n',char(10)),'#RentVsOwn','branded_card','publish','published','[]','Man gives tour of ''smallest apartment in Paris''; rent leaves people stunned','The card concept is genuinely clever — ''134 seedhiyan chadhoge… ya EMI bharoge?'' is a punchy, visual contrast that earns its scroll-stop. The split-card format (unka ghar vs apna ghar) is well-executed and the Paris trend hook is timely. However, the caption partially repeats the card''s logic (''Same ₹67K EMI mein apna ghar + lift bhi'') rather than closing it with a kicker — it explains the joke instead of landing it. Compare to the approved AI Ghibli example where the caption pivots sharply (''that''s the real glow-up'') without restating the card. The ''Maths kar lo 👉'' CTA is functional but flat. On hashtags: ''#SmallestApartmentInParis'' is the actual trending hashtag and should be first — ''#RentVsOwn'' is a generic evergreen tag, not the trend driving this moment. The list also hits 18 tags (within range) but includes weak filler like ''#HousingForAll'' and the misspelled ''#MilenialMoney'' that dilute credibility.','{"card_hook_strength": 7.5, "trend_and_shareability": 7.0, "caption_punch": 6.5, "hashtag_strategy": 6.5}','Strong hook with relatable humour (134 stairs vs EMI comparison) that creates immediate cognitive friction and FOMO. The Rent vs Own narrative is evergreen and resonates with millennial/GenZ audiences. Emotional appeal (aspiration + practical wisdom) is well-balanced. However, the Paris reference feels slightly disconnected from core Indian audience intent—may confuse rather than clarify. CTA is present but indirect (''Link in bio''). Hashtag strategy is solid but slightly over-optimised (#SmallestApartmentInParis feels forced). The meme-card format performs well on Instagram, and the bilingual Hindi-English copy broadens reach. Predicted engagement sits in ''Good'' range (6-8%) rather than Viral due to niche appeal (home loan seekers) and weak geographic specificity.','{"hashtag": "#RentVsOwn", "volume": "rising", "platform": "twitter", "context": "The Paris apartment video is reigniting the global debate on sky-high rents vs. the value of buying property in metro cities.", "creative_hook": "134 seedhiyan chadhoge ya EMI bharoge? \ud83e\udd14 At \u20b967,000/month rent you''re literally funding someone else''s property. Housing.com Home Loans \u2014 same EMI, apna ghar, apna lift. Do the math. \ud83d\udcca\ud83c\udfe0", "city_hint": null, "tags": ["homeloan", "emi", "investment", "finance", "viral"]}','{"media_format": "branded_card", "meme_concept": "", "card_text": "134 seedhiyan chadhoge\u2026\nya EMI bharoge? \ud83e\udd14\nRent = unka ghar. EMI = apna ghar. \ud83c\udfe0", "trend_hashtag": "#RentVsOwn", "city_hint": null, "city_link": null, "alt_text": "Branded card showing a split comparison: left side depicts a cramped Paris micro-apartment with a steep 134-step staircase, labeled ''Rent \u2013 unka ghar''; right side shows a modern Indian apartment building with a lift, labeled ''EMI \u2013 apna ghar''. Overlay text reads: ''134 seedhiyan chadhoge\u2026 ya EMI bharoge? \ud83e\udd14''. Housing.com logo and Home Loans CTA at the bottom."}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/812ebb27/instagram_b2c3d4e5.png');
INSERT INTO published_posts VALUES(174,'1691954f-3a97-4795-8f67-f5ac891408c8','58dcf57e','twitter','dry_run_1691954f','dry_run','output/58dcf57e/published/twitter_1691954f.md','2026-05-19 02:27:02.056624','Rasgulla wale Delhi mein rehte hain. Idli wale Hyderabad mein. Debate khatam — dono sahi hain, ghar toh dono ko chahiye 🏡 housing.com/in/buy/new-delhi','["#RasgullaVsIdli", "#DelhiVsHyderabad", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "delhi", "page_type": "city_srp", "placement": "tweet"}]','[]','Reframes the viral North vs South food war as the REAL question buyers should ask — Delhi flat ya Hyderabad villa? Uses the debate format to make property comparison feel native to the trend.',1,0.0,6.0,0.0,4.900000000000000355,8500,52,18,34,1.199999999999999956,1.300000000000000044,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Rasgulla vs Idli chhodo 🍡🥟\nAsli debate: Delhi ka 2BHK ya Hyderabad ka villa? 🏡\nIsska jawab sirf Housing.com pe milega.','\n',char(10)),'#RasgullaVsIdli','meme_overlay','publish','published','[]','Trending · Shashi Tharoor defends idli after viral rasgulla post','The post attempts to ride the Rasgulla vs Idli food debate trend but immediately abandons it in the very next line — ''Asli debate: Delhi ka 2BHK vs Hyderabad ka villa?'' This pivot kills the trend hook. The food debate was the cultural moment; the real estate comparison is a forced substitute, not a punchline that emerges from it. The phrase ''Iska jawab sirf Housing.com pe milega'' is a classic bolted-on CTA — it reads like the ''AVOID THIS'' pattern of ''Pakistan ke match ke baad, Housing.com pe apna ghar dhundho.'' There''s no wit or wordplay connecting rasgulla/idli to homes; the trend is used as a thin wrapper and then discarded. Compared to the approved RCB example (''Tum apna ghar kab jeeto ge?'') where the housing punchline flows naturally from the trend emotion, this post replaces the trend rather than extending it. The Hinglish is present but the construction is stiff and the joke doesn''t land — there''s no surprise or twist that would make a GenZ user screenshot or quote-tweet this.','{"character_compliance": 10.0, "trend_dominance": 4.5, "shareability": 4.0, "hinglish_wit": 5.0, "cta_quality": 6.0}','Strong hook with regional food analogy (Rasgulla vs Idli) creates immediate curiosity and relatability for Indian audience. ''Asli debate'' positions real estate as the *real* conversation, leveraging FOMO and aspiration. Wit-based hook performs well on Twitter. However, lacks visual asset (no image) which typically boosts engagement by 25-35%. CTA is clear but URL shortening could improve click-through. Hashtags are relevant but #RasgullaVsIdli may dilute focus from core real estate message. Hyderabad villa vs Delhi 2BHK comparison taps into inter-city rivalry sentiment, driving comments/debate.','{"hashtag": "#RasgullaVsIdli", "volume": "high", "platform": "twitter", "context": "The viral food comparison sparked a massive online debate with thousands taking sides between the South Indian and Bengali delicacies.", "creative_hook": "Twitter is fighting over Rasgulla vs Idli but we''re out here asking the REAL question \ud83e\udd14 \u2014 Chennai flat or Kolkata flat? Both cities are rising faster than sugar syrup \ud83d\udcc8 Stop debating food, start investing in real estate where the returns are SWEET \ud83c\udfe1 #HousingForAll", "city_hint": null, "tags": ["viral", "chennai", "investment", "infrastructure"]}','{"main_tweet": "Rasgulla vs Idli chhodo \ud83c\udf61 Asli debate: Delhi ka 2BHK vs Hyderabad ka villa? Iska jawab sirf Housing.com pe milega \ud83c\udfe1 housing.com/in/buy/new-delhi", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 144, "include_image": false, "revision_summary": "Kept the Rasgulla vs Idli rivalry as the dominant hook, bridged it naturally to city identity and the universal need for a home, and replaced the hard-sell CTA with a soft, witty punchline that makes the housing link feel like an organic afterthought.", "revised": true}',NULL);
INSERT INTO published_posts VALUES(175,'6f4e4123-8253-4585-964c-b068bba5eef3','58dcf57e','instagram','dry_run_6f4e4123','dry_run','output/58dcf57e/published/instagram_6f4e4123.md','2026-05-19 02:27:02.059352','Rasgulla vs Idli chhodo 🍡🥟 asli debate: Delhi 2BHK vs Hyderabad villa? 🏡 Tu kis side hai? housing.com/in/buy/new-delhi 🔗','["#RasgullaVsIdli", "#HousingDotCom", "#GharKhojna", "#NorthVsSouth", "#DelhiVsHyderabad", "#RealEstateIndia", "#DelhiHomes", "#HyderabadHomes", "#2BHKDelhi", "#VillaLife", "#GharWar", "#HomeBuying", "#PropertyIndia", "#DelhiRealEstate", "#HyderabadRealEstate", "#IndianHomes", "#BuyProperty", "#NorthIndiaVsSouthIndia"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "delhi", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/58dcf57e/instagram_a1f2c3d4_meme_placeholder.png"]','Reframes the viral North vs South food war as the REAL question buyers should ask — Delhi flat ya Hyderabad villa? Uses the debate format to make property comparison feel native to the trend.',1,0.0,0.0,0.0,6.599999999999999645,45000,1890,405,675,2.799999999999999823,4.200000000000000177,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Rasgulla vs Idli chhodo 🍡🥟\nAsli debate: Delhi ka 2BHK ya Hyderabad ka villa? 🏡\nIsska jawab sirf Housing.com pe milega.','\n',char(10)),'#RasgullaVsIdli','meme_overlay','publish','published','[]','Trending · Shashi Tharoor defends idli after viral rasgulla post','The meme format and North vs South cultural hook are solid instincts — the split-screen rasgulla/idli concept is genuinely shareable and the housing pivot (Delhi 2BHK vs Hyderabad villa) is more organically connected than a bolted-on CTA. However, the card text stumbles on its closing line: ''Isska jawab sirf Housing.com pe milega'' is a weak, generic closer that deflates the wit built up by the food-fight setup — it reads like a banner ad punchline, not a meme payoff. The caption then repeats the card''s premise almost verbatim (''Rasgulla vs Idli chhodo 🍡🥟 asli debate'') instead of closing with a kicker, and the URL is dropped mid-sentence without a clean CTA beat. Compared to the approved examples — which land a sharp one-liner on the card and let the caption do a tight pivot — this post''s card-caption unit feels like two halves that don''t snap together. The hashtag count (18) is within range and #RasgullaVsIdli leads correctly.','{"card_hook_strength": 6.5, "trend_and_shareability": 7.0, "caption_punch": 5.5, "hashtag_strategy": 7.5}','Strong hook with dual viral trends (Rasgulla vs Idli + North vs South debate) creates immediate scroll-stop potential. Meme format is proven high-engagement vehicle on Instagram. Regional pride angle (Delhi vs Hyderabad) drives comment volume and shares. However, relevance of Rasgulla vs Idli trend may be cooling depending on current date—if trend peaked 2-3 weeks ago, engagement drops 15-20%. CTA is present but indirect (link in caption rather than explicit ''tap to explore''). Emotional drivers are strong (regional FOMO, aspiration, humour) but real estate product integration feels slightly forced—users engaging with meme may not convert to property interest immediately. Hashtag strategy is solid (17 tags, mix of trending + niche) but slightly over-optimized.','{"hashtag": "#RasgullaVsIdli", "volume": "high", "platform": "twitter", "context": "The viral food comparison sparked a massive online debate with thousands taking sides between the South Indian and Bengali delicacies.", "creative_hook": "Twitter is fighting over Rasgulla vs Idli but we''re out here asking the REAL question \ud83e\udd14 \u2014 Chennai flat or Kolkata flat? Both cities are rising faster than sugar syrup \ud83d\udcc8 Stop debating food, start investing in real estate where the returns are SWEET \ud83c\udfe1 #HousingForAll", "city_hint": null, "tags": ["viral", "chennai", "investment", "infrastructure"]}','{"media_format": "meme_overlay", "meme_concept": "Use the viral split-screen meme format showing rasgulla on one side and idli on the other (currently trending on X/Insta). Overlay our text on top. Alternatively, use the ''two buttons sweating'' meme with ''Delhi flat'' and ''Hyderabad villa'' on the buttons.", "card_text": "Rasgulla vs Idli chhodo \ud83c\udf61\ud83e\udd5f\nAsli debate: Delhi ka 2BHK ya Hyderabad ka villa? \ud83c\udfe1\nIsska jawab sirf Housing.com pe milega.", "trend_hashtag": "#RasgullaVsIdli", "city_hint": "delhi", "city_link": "https://housing.com/in/buy/new-delhi", "alt_text": "Meme overlay image split into two sides: left side shows a rasgulla icon with text ''Delhi ka 2BHK'' and right side shows an idli icon with text ''Hyderabad ka Villa'', styled as a North vs South debate meme with Housing.com branding at the bottom."}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/58dcf57e/instagram_a1f2c3d4_meme_placeholder.png');
INSERT INTO published_posts VALUES(176,'cf261d29-1772-472a-aa55-5ad7628b6aad','58dcf57e','twitter','dry_run_cf261d29','dry_run','output/58dcf57e/published/twitter_cf261d29.md','2026-05-19 02:27:02.060725','Rasgulla vs Idli debate toh theek hai 🍡 but asli sawaal yeh hai — Delhi ka 2BHK mein rasgulla khaoge ya Hyderabad ke villa mein idli? 👀 housing.com/in/buy/new-delhi','["#RasgullaVsIdli", "#DelhiVsHyderabad", "#HousingDotCom"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "delhi", "page_type": "city_srp", "placement": "tweet"}]','[]','Reframes the viral North vs South food war as the REAL question buyers should ask — Delhi flat ya Hyderabad villa? Uses the debate format to make property comparison feel native to the trend.',1,0.0,6.0,0.0,5.0,8500,52,18,34,2.100000000000000088,1.300000000000000044,0.7199999999999999734,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Rasgulla vs Idli chhodo 🍡🥟\nAsli debate: Delhi ka 2BHK ya Hyderabad ka villa? 🏡\nIsska jawab sirf Housing.com pe milega.','\n',char(10)),'#RasgullaVsIdli','meme_overlay','publish','published','[]','Trending · Shashi Tharoor defends idli after viral rasgulla post','The core problem: ''Rasgulla vs Idli'' is a thin, generic food-debate hook — it''s not tied to any specific viral moment, trending news, or cultural flashpoint happening right now. It reads like Housing.com invented a fake debate just to pivot to real estate, which is exactly the ''bolted-on'' failure pattern. The pivot line ''Asli debate: Delhi ka 2BHK ya Hyderabad ka villa?'' immediately hijacks the food hook and replaces it with a housing message — so the trend is NOT the hero, the housing angle is. Compare to the approved RCB example: the trend (RCB winning the cup after 18 years) is the entire emotional payload, and ''Tum apna ghar kab jeeto ge?'' is a one-line punchline that emerges from it. Here, the food debate is discarded in the same sentence it''s introduced. The Hinglish is functional (''chhodo'', ''Asli debate'', ''Ek sahi comparison karo'') but ''Ek sahi comparison karo'' feels like a mild call-to-action dressed as wit — it''s not a punchline, it''s a nudge. A GenZ user would not RT this because there''s no surprise, no twist, and no emotional resonance — it''s a comparison prompt, not a cultural moment. Two emojis are used correctly, but the 🏡 at the end feels like a real estate ad sign-off.','{"character_compliance": 10.0, "trend_dominance": 4.5, "shareability": 4.0, "hinglish_wit": 5.5, "cta_quality": 6.0}','Strong hook with cultural wit (Rasgulla vs Idli) that pivots to real estate comparison—creates curiosity and relatability for Indian audience. Delhi vs Hyderabad comparison taps into regional pride/FOMO. However, engagement held back by: (1) No visual asset (image/video would boost 40-60%), (2) Mild CTA (link-only, no urgency), (3) Thread format missing—single tweet limits comment depth. Hashtags are relevant but #RasgullaVsIdli may dilute focus. Predicted 1.3% ER is solid for Housing.com baseline (0.8%) but below ''Good'' threshold (2-4%) due to execution gaps.','{"hashtag": "#RasgullaVsIdli", "volume": "high", "platform": "twitter", "context": "The viral food comparison sparked a massive online debate with thousands taking sides between the South Indian and Bengali delicacies.", "creative_hook": "Twitter is fighting over Rasgulla vs Idli but we''re out here asking the REAL question \ud83e\udd14 \u2014 Chennai flat or Kolkata flat? Both cities are rising faster than sugar syrup \ud83d\udcc8 Stop debating food, start investing in real estate where the returns are SWEET \ud83c\udfe1 #HousingForAll", "city_hint": null, "tags": ["viral", "chennai", "investment", "infrastructure"]}','{"main_tweet": "Rasgulla vs Idli chhodo \ud83c\udf61 Asli debate: Delhi ka 2BHK ya Hyderabad ka villa? Ek sahi comparison karo \u2014 housing.com/in/buy/new-delhi \ud83c\udfe1", "thread": [], "is_thread": false, "hook_type": "wit", "char_count": 132, "include_image": false, "revision_summary": "Kept the food debate alive through the entire tweet and made the housing angle emerge as the comic twist punchline \u2014 city + food combo \u2014 instead of abandoning the hook mid-sentence; dropped the instructional CTA.", "revised": true}',NULL);
INSERT INTO published_posts VALUES(177,'fbaed236-bcd8-4d15-a68b-b7b3cfe9fa75','58dcf57e','instagram','dry_run_fbaed236','dry_run','output/58dcf57e/published/instagram_fbaed236.md','2026-05-19 02:27:02.061829','Rasgulla vs Idli chhodo 🍡🥟 asli debate hai — Delhi 2BHK ya Hyderabad villa? 🏡 Tu kis side hai? Link in bio 🔗','["#RasgullaVsIdli", "#HousingDotCom", "#GharKhojna", "#NorthVsSouth", "#DelhiVsHyderabad", "#RealEstateIndia", "#DelhiHomes", "#HyderabadHomes", "#2BHKVsVilla", "#GharWarShuru", "#HomeBuying", "#DelhiRealEstate", "#HyderabadRealEstate", "#PropertyInIndia", "#IndianHomeBuyers", "#GharKaSapna", "#NorthIndiaVsSouthIndia"]','[{"url": "https://housing.com/in/buy/new-delhi", "anchor_text": "delhi", "page_type": "city_srp", "placement": "caption"}]','["https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/58dcf57e/instagram_a1f2c3d4_meme_placeholder.png"]','Reframes the viral North vs South food war as the REAL question buyers should ask — Delhi flat ya Hyderabad villa? Uses the debate format to make property comparison feel native to the trend.',1,0.0,0.0,0.0,6.700000000000000177,45000,2100,680,890,4.200000000000000177,8.400000000000000355,0.7800000000000000266,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'social',replace('Rasgulla vs Idli chhodo 🍡🥟\nAsli debate: Delhi ka 2BHK ya Hyderabad ka villa? 🏡\nIsska jawab sirf Housing.com pe milega.','\n',char(10)),'#RasgullaVsIdli','meme_overlay','publish','published','[]','Trending · Shashi Tharoor defends idli after viral rasgulla post','The trend-jack is clever in concept — using Rasgulla vs Idli as a proxy for Delhi vs Hyderabad is genuinely witty and culturally loaded. But the execution loses its nerve halfway. The card text commits the ''paragraph-length'' sin with three lines that dilute the punchline: ''Isska jawab sirf Housing.com pe milega'' is a bolted-on CTA that kills the meme energy — it reads like a banner ad sneaking into a meme format. The caption (''Tu kis side hai? Link in bio 🔗'') is the weakest line in the whole post — it''s a generic engagement-bait closer that any brand could write, and it doesn''t close what the card opened. Compare to the approved ''Sarkar badli. Delhi ka vibe badla.'' — that card lands a complete thought in 6 words. This card needs 3 lines to say the same thing and still ends on a corporate note. The meme format choice (split-screen or two-buttons) is strong, but the overlay text overwrites the joke instead of letting the visual do the work. Hashtag count (17) is within range and trend tag is correctly placed first.','{"card_hook_strength": 6.5, "trend_and_shareability": 7.0, "caption_punch": 6.0, "hashtag_strategy": 7.5}','Strong hook leveraging viral food meme format (Rasgulla vs Idli) to bait North-South regional debate—proven scroll-stopper on Indian Instagram. Meme overlay format aligns with platform trends. High emotional resonance: aspiration (villa fantasy), regional pride, and humour drive comments/shares. ''Tu kis side hai?'' creates direct participation incentive. However, confidence capped at 0.78 due to: (1) CTA is weak (''Link in bio'') vs direct engagement ask, (2) relevance of food meme to real estate feels slightly forced—may confuse intent, (3) no urgency/scarcity element. Hashtag density (17 tags) is solid but #RasgullaVsIdli may dilute Housing.com brand recall.','{"hashtag": "#RasgullaVsIdli", "volume": "high", "platform": "twitter", "context": "The viral food comparison sparked a massive online debate with thousands taking sides between the South Indian and Bengali delicacies.", "creative_hook": "Twitter is fighting over Rasgulla vs Idli but we''re out here asking the REAL question \ud83e\udd14 \u2014 Chennai flat or Kolkata flat? Both cities are rising faster than sugar syrup \ud83d\udcc8 Stop debating food, start investing in real estate where the returns are SWEET \ud83c\udfe1 #HousingForAll", "city_hint": null, "tags": ["viral", "chennai", "investment", "infrastructure"]}','{"media_format": "meme_overlay", "meme_concept": "Use the viral split-screen meme format showing rasgulla on one side and idli on the other (currently trending on X/Insta). Overlay our text on top. Alternatively, use the ''two buttons sweating'' meme with ''Delhi flat'' and ''Hyderabad villa'' on the buttons.", "card_text": "Rasgulla vs Idli chhodo \ud83c\udf61\ud83e\udd5f\nAsli debate: Delhi ka 2BHK ya Hyderabad ka villa? \ud83c\udfe1\nIsska jawab sirf Housing.com pe milega.", "trend_hashtag": "#RasgullaVsIdli", "city_hint": "delhi", "city_link": "https://housing.com/in/buy/new-delhi", "alt_text": "Meme-style graphic split into two sides. Left side shows Delhi 2BHK with Rasgulla emoji, right side shows Hyderabad villa with Idli emoji. Overlay text reads: Rasgulla vs Idli chhodo \u2014 asli debate hai Delhi 2BHK ya Hyderabad villa. Housing.com branding at the bottom."}','https://pub-f574a876869d4654b354fad0d657b289.r2.dev/housing-marketeer/58dcf57e/instagram_a1f2c3d4_meme_placeholder.png');
